INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-3-01-lesson-06','cognizen-crypto-mastery-foundations-production','Spot Versus Derivative Trend Following and Relative Strength','cmf-module-3-01','text','### Spot Versus Derivative Trend Following\n\n\n\n### Spot Strategy\n\nUses owned assets.\n\nPotential characteristics:\n\nNo forced liquidation without borrowing\n\nSimpler custody\n\nLimited ability to profit directly from declines\n\nFull capital required\n\n### Derivative Strategy\n\nUses futures, perpetuals or options.\n\nPotential characteristics:\n\nLong and short exposure\n\nLeverage\n\nCapital efficiency\n\nFunding and basis risk\n\nLiquidation\n\nCounterparty dependence\n\nThe market signal may be the same while the instrument changes the risk significantly.\n\n### Funding Rates and Trend Following\n\nIn perpetual futures, funding payments help align contract prices with spot markets.\n\nDuring a strong bullish trend:\n\nLong positions may pay high funding\n\nHolding costs increase\n\nCrowded positioning may develop\n\nDuring a bearish trend:\n\nShort positions may pay funding\n\nShorting costs can rise\n\nA correct directional trend may still produce disappointing returns after prolonged funding costs.\n\nTrend analysis should include the selected instrument’s carrying cost.\n\n### Open Interest\n\nOpen interest measures outstanding derivative positions.\n\nRising price with rising open interest may indicate new leveraged participation.\n\nHowever, this can also create liquidation risk.\n\nA trend supported by excessive leverage may reverse violently.\n\nTrend followers should distinguish between:\n\nSpot-driven demand\n\nLeveraged derivative expansion\n\nShort covering\n\nLiquidation-driven movement\n\nThis will be explored in later derivatives modules.\n\n### Liquidation Cascades\n\nA trend may accelerate when leveraged positions are forced to close.\n\nIn an upward move:\n\nShort liquidations create additional buying\n\nIn a downward move:\n\nLong liquidations create additional selling\n\nThese cascades can produce powerful trends.\n\nThey can also end abruptly when forced activity is exhausted.\n\nAn entry after a large liquidation move may be poorly timed even when the broader trend remains intact.\n\n### Market Regimes\n\nA trend-following system does not perform equally in every environment.\n\nCommon regimes include:\n\nStrong directional trend\n\nWeak trend\n\nSideways range\n\nHigh-volatility reversal\n\nLow-volatility compression\n\nIlliquid market\n\nNews-driven market\n\nTrend-following performance is usually strongest when:\n\nDirection persists\n\nPullbacks remain controlled\n\nLiquidity is adequate\n\nMarket participation supports continuation\n\nIt is usually weakest when direction changes repeatedly.\n\n### Regime Detection\n\nPossible regime tools include:\n\nMarket structure\n\nMoving-average slope\n\nADX\n\nVolatility\n\nRange boundaries\n\nTrend persistence\n\nCorrelation\n\nVolume\n\nNo regime detector is perfect.\n\nBy the time the trend regime is confirmed, some of the movement has already occurred.\n\nThe goal is to improve alignment, not predict the regime with certainty.\n\n### Trend Persistence\n\nTrend persistence describes how likely directional movement is to continue over time.\n\nPersistence may be supported by:\n\nStrong network or macro catalyst\n\nConsistent institutional flows\n\nExpanding participation\n\nReduced opposing liquidity\n\nMarket-wide risk appetite\n\nRepeated support or resistance defence\n\nPrice-based strategies do not need to identify every cause.\n\nUnderstanding the environment may improve risk awareness.\n\n### Fundamental Support for a Trend\n\nA price trend may be supported by:\n\nAdoption growth\n\nRevenue growth\n\nNetwork usage\n\nRegulatory clarity\n\nSupply reduction\n\nInstitutional demand\n\nImproving liquidity\n\nA fundamentally supported trend may be more durable.\n\nHowever, fundamentals can be known and fully priced in.\n\nA strong narrative can also produce a trend far beyond reasonable valuation.\n\nTrend following follows price but should remain aware of fundamental event risk.\n\n### On-Chain Support for a Trend\n\nOn-chain evidence may help evaluate whether a cryptocurrency trend is supported by:\n\nActive addresses\n\nTransaction activity\n\nLong-term holder behaviour\n\nExchange inflows and outflows\n\nRealised profit and loss\n\nNetwork fees\n\nStablecoin liquidity\n\nOn-chain data can provide useful context.\n\nIt does not guarantee price continuation.\n\nMetrics can be delayed, manipulated or difficult to interpret.\n\nAdvanced on-chain analysis will be covered later in Course 3.\n\n### Macroeconomic Support for a Trend\n\nDigital asset trends can be influenced by:\n\nInterest rates\n\nGlobal liquidity\n\nCurrency strength\n\nRisk appetite\n\nInflation expectations\n\nCredit conditions\n\nRegulatory developments\n\nA strong cryptocurrency trend may weaken when broader financial conditions change.\n\nMacro analysis can support scenario planning.\n\nIt should not replace price-based invalidation.\n\n### Cross-Asset Confirmation\n\nA cryptocurrency trend may be compared with:\n\nBitcoin\n\nStablecoin flows\n\nEquity markets\n\nBond yields\n\nCurrency indexes\n\nCommodity markets\n\nSector-related tokens\n\nBroad participation can strengthen a trend interpretation.\n\nHowever, correlations change.\n\nOne asset can diverge from the broader market because of project-specific events.\n\n### Bitcoin and Altcoin Trend Context\n\nMany digital assets remain influenced by Bitcoin’s trend.\n\nAn altcoin may show bullish local structure while Bitcoin remains in a strong decline.\n\nThis creates conflicting evidence.\n\nPossible considerations include:\n\nBitcoin trend\n\nBitcoin dominance\n\nRelative strength of the altcoin\n\nSector rotation\n\nLiquidity\n\nToken-specific catalysts\n\nA trend should be assessed both in its quote currency and relative to major market benchmarks.\n\n### Relative Strength\n\nRelative strength compares one asset’s performance with another.\n\nSuppose Token A rises ten percent while the broader market rises twenty percent.\n\nToken A is rising in absolute terms but underperforming relatively.\n\nA strong trend candidate may show:\n\nUptrend against a stable quote asset\n\nUptrend relative to a benchmark\n\nImproving volume\n\nStronger recovery after corrections\n\nRelative strength can help identify where market demand is concentrated.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,6,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-3-01-lesson-07','cognizen-crypto-mastery-foundations-production','Trend Following Across a Portfolio and Tax and Turnover','cmf-module-3-01','text','### Trend Following Across a Portfolio\n\nA multi-asset trend strategy may apply the same rules to several markets.\n\nPotential benefits include:\n\nGreater chance of capturing a trend\n\nDiversification across opportunities\n\nReduced dependence on one asset\n\nPotential risks include:\n\nCorrelations rising during stress\n\nSeveral signals expressing the same market view\n\nExcessive total exposure\n\nIncreased fees and monitoring\n\nPositions should be grouped by underlying risk.\n\nTen bullish crypto signals may represent one broad risk-on trade.\n\n### Correlated Trend Signals\n\nSuppose a strategy enters long positions in:\n\nBitcoin\n\nSeveral smart contract platforms\n\nDeFi tokens\n\nGaming tokens\n\nEach position may meet the technical rules.\n\nA broad market decline can affect all of them simultaneously.\n\nRisk per position must be combined with:\n\nTotal open risk\n\nSector exposure\n\nEcosystem exposure\n\nCorrelation\n\nIndependent signals do not necessarily produce independent risk.\n\n### Risk Per Trade\n\nA trend-following strategy should define the maximum loss per position.\n\nThe amount may be expressed as:\n\nPercentage of capital\n\nFixed monetary amount\n\nVolatility-adjusted risk unit\n\nA simplified formula is:\n\nPosition size = Maximum capital risk ÷ Distance to stop\n\nSuppose:\n\nCapital: 100,000 units\n\nMaximum risk: 1 percent\n\nRisk amount: 1,000 units\n\nEntry: 50\n\nStop: 45\n\nRisk per token: 5\n\nPosition quantity:\n\n1,000 ÷ 5 = 200 tokens\n\nPosition value:\n\n200 × 50 = 10,000 units\n\n### Volatility-Based Position Sizing\n\nA volatility-based approach reduces position size as normal market movement increases.\n\nSuppose:\n\nAsset A has a two-unit stop distance\n\nAsset B has a ten-unit stop distance\n\nMaximum capital risk is the same\n\nAsset B receives a smaller quantity.\n\nThis helps prevent a volatile asset from dominating portfolio risk.\n\nVolatility sizing does not address:\n\nSmart contract risk\n\nExchange risk\n\nToken failure\n\nIlliquidity\n\nAdditional limits remain necessary.\n\n### Portfolio Heat\n\nPortfolio heat is the total planned risk across open positions.\n\nSuppose:\n\nPosition 1 risks one percent\n\nPosition 2 risks one percent\n\nPosition 3 risks one percent\n\nPosition 4 risks one percent\n\nTotal planned open risk is approximately four percent, assuming all stops execute as expected.\n\nIf the positions are highly correlated, actual combined loss may be greater because:\n\nMarkets move together\n\nSlippage increases\n\nLiquidity weakens\n\nStops execute poorly\n\nA portfolio heat limit prevents many acceptable individual positions from creating unacceptable total risk.\n\n### Adding to Winning Positions\n\nSome trend-following systems add to profitable positions.\n\nThis is known as pyramiding.\n\nA disciplined approach may:\n\nAdd only after price confirms continuation\n\nKeep total risk within a predefined limit\n\nRaise protective stops\n\nLimit the number of additions\n\nReduce the size of each addition\n\nAdding to winners can increase exposure to strong trends.\n\nIt can also concentrate risk near the end of a move.\n\n### Adding to Losing Positions\n\nAdding to a losing trend position usually contradicts a risk-based trend-following framework.\n\nIf the entry signal fails, the position should generally be closed according to the plan.\n\nRepeatedly adding can turn:\n\nA small planned loss\n\nInto a large unplanned exposure\n\nThe strategy should not depend on the market eventually returning to the entry.\n\n### Initial Stop\n\nThe initial stop defines the point at which the setup is considered unsuccessful.\n\nIt may be based on:\n\nStructural low or high\n\nATR multiple\n\nBreakout failure\n\nChannel level\n\nMoving average\n\nMaximum holding period\n\nThe initial stop should be determined before entry.\n\nThe position size should then be calculated from that distance.\n\n### Catastrophic Stop\n\nA catastrophic stop protects against an extreme loss when the normal exit system fails.\n\nIt may be placed farther away than the ordinary trading stop.\n\nPotential uses include:\n\nExchange order failure\n\nSudden market gap\n\nAutomated-system malfunction\n\nLoss of connectivity\n\nA stop order is not guaranteed.\n\nIn severe conditions, execution can occur at a worse price.\n\n### Stop Orders and Slippage\n\nDuring rapid movement, a stop-market order may execute below the trigger for a long position or above it for a short position.\n\nThis creates slippage.\n\nA stop-limit order controls the minimum or maximum execution price.\n\nHowever, it may remain unfilled.\n\nTrend-following risk calculations should include realistic execution assumptions.\n\n### Entry Costs\n\nTrend-following strategies may trade frequently during range-bound markets.\n\nCosts can include:\n\nTrading fees\n\nSpread\n\nSlippage\n\nFunding\n\nBorrowing\n\nNetwork fees\n\nTax consequences\n\nA system with positive performance before costs may become unprofitable after costs.\n\nBacktesting should include reasonable execution assumptions.\n\n### Tax and Turnover\n\nFrequent entries and exits may create:\n\nTaxable disposals\n\nRecord-keeping burden\n\nShorter holding periods\n\nHigher accounting complexity\n\nA trend strategy should be evaluated after tax where possible.\n\nThe most technically efficient system may not produce the best after-tax outcome.\n\nTax treatment depends on jurisdiction.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,7,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-3-01-lesson-08','cognizen-crypto-mastery-foundations-production','Systematic Trend Following and Performance Metrics','cmf-module-3-01','text','### Systematic Trend Following\n\nA systematic strategy uses explicit rules.\n\nFor example:\n\nBuy when price closes above a fifty-day high\n\nExit when price closes below a twenty-day low\n\nRisk one percent per position\n\nEnter only when the long-term moving average is rising\n\nPotential advantages include:\n\nConsistency\n\nTestability\n\nReduced emotional discretion\n\nClear execution\n\nPotential limitations include:\n\nModel risk\n\nParameter sensitivity\n\nRegime change\n\nTechnology failure\n\nOverfitting\n\nA rule-based strategy still requires monitoring and governance.\n\n### Discretionary Trend Following\n\nA discretionary participant interprets market structure and context rather than following entirely mechanical rules.\n\nThey may consider:\n\nQuality of breakout\n\nMarket narrative\n\nVolume\n\nBroader market conditions\n\nNews\n\nRelative strength\n\nLiquidity\n\nPotential advantages include:\n\nFlexibility\n\nAdaptation\n\nContext awareness\n\nPotential limitations include:\n\nInconsistency\n\nEmotional bias\n\nDifficult backtesting\n\nSelective memory\n\nUnclear rules\n\nA discretionary method should still document its decision criteria.\n\n### Hybrid Trend Following\n\nA hybrid approach combines systematic and discretionary elements.\n\nFor example:\n\nSystematic screening identifies trend candidates\n\nDiscretionary review evaluates liquidity and context\n\nPosition size follows a fixed risk formula\n\nExits use objective trailing rules\n\nThis can balance consistency with market awareness.\n\nIt may also create ambiguity if discretion repeatedly overrides losing signals while accepting winning ones.\n\nThe boundaries of discretion should be defined.\n\n### Parameter Selection\n\nTrend systems require settings such as:\n\nMoving-average length\n\nBreakout period\n\nATR multiple\n\nTrailing-stop length\n\nADX threshold\n\nThese settings affect:\n\nSignal frequency\n\nEntry speed\n\nStop distance\n\nAverage holding period\n\nWhipsaw rate\n\nThere is no universally optimal parameter.\n\nSettings should have a logical relationship to the intended timeframe and be tested across several market conditions.\n\n### Overfitting\n\nOverfitting occurs when a strategy is adjusted until it matches historical data too closely.\n\nWarning signs include:\n\nMany rules\n\nUnusual parameter values\n\nExcellent performance on one token\n\nWeak performance after small setting changes\n\nExclusion of unfavourable periods\n\nNo allowance for costs\n\nA robust trend system should perform reasonably across:\n\nNearby parameters\n\nDifferent assets\n\nDifferent market cycles\n\nUnseen data\n\nHistorical perfection is usually suspicious.\n\n### Backtesting\n\nBacktesting applies the strategy rules to historical data.\n\nA valid backtest should define:\n\nExact entry\n\nExact exit\n\nPosition sizing\n\nFees\n\nSlippage\n\nData source\n\nAsset universe\n\nReinvestment rules\n\nDelisting treatment\n\nIt should evaluate:\n\nTotal return\n\nDrawdown\n\nWin rate\n\nPayoff ratio\n\nExpectancy\n\nNumber of trades\n\nTime in market\n\nLosing streaks\n\nBacktesting does not prove future profitability.\n\nIt reveals how the rules would have behaved under selected historical conditions.\n\n### Look-Ahead Bias\n\nLook-ahead bias occurs when the test uses information that would not have been available at the time of the decision.\n\nExamples include:\n\nEntering at a closing price before the candle actually closed\n\nUsing future index constituents\n\nSelecting assets known later to have survived\n\nUsing revised data\n\nLook-ahead bias can make results appear unrealistically strong.\n\n### Survivorship Bias\n\nSurvivorship bias occurs when the test includes only assets that exist today.\n\nFailed, delisted or abandoned tokens are omitted.\n\nThis exaggerates historical performance because the strategy avoids markets that disappeared.\n\nA realistic cryptocurrency backtest should consider:\n\nDelistings\n\nToken failures\n\nLiquidity collapse\n\nContract migrations\n\nExchange closures\n\n### Selection Bias\n\nSelection bias occurs when the researcher chooses assets or periods because they support the desired conclusion.\n\nFor example:\n\nTesting only strong bull-market tokens\n\nExcluding sideways periods\n\nSelecting one successful indicator setting\n\nIgnoring failed deployments\n\nA strategy should be tested on a broad and logically defined sample.\n\n### In-Sample and Out-of-Sample Testing\n\n\n\n### In-Sample Data\n\nUsed to develop or calibrate the strategy.\n\n### Out-of-Sample Data\n\nReserved to evaluate the strategy after the rules have been selected.\n\nStrong in-sample performance and weak out-of-sample performance may indicate overfitting.\n\nA strategy should also be tested through real-time paper trading before substantial capital is committed.\n\n### Walk-Forward Testing\n\nWalk-forward testing repeatedly:\n\nDevelops the system using one historical period\n\nTests it on the next unseen period\n\nMoves the window forward\n\nRepeats the process\n\nThis can provide a more realistic view of how a strategy adapts over time.\n\nIt does not eliminate model risk.\n\n### Paper Trading\n\nPaper trading applies the strategy without risking real capital.\n\nIt can test:\n\nSignal generation\n\nOrder process\n\nRecord-keeping\n\nEmotional reactions\n\nOperational reliability\n\nPaper trading cannot reproduce fully:\n\nReal slippage\n\nLiquidity pressure\n\nFear\n\nGreed\n\nExchange failure\n\nIt should be followed by small-scale live testing before larger deployment.\n\n### Performance Metrics\n\nA trend strategy should not be judged only by total return.\n\nImportant metrics include:\n\nMaximum drawdown\n\nVolatility\n\nSharpe ratio\n\nSortino ratio\n\nCalmar ratio\n\nWin rate\n\nPayoff ratio\n\nProfit factor\n\nExpectancy\n\nExposure\n\nTurnover\n\nLongest losing streak\n\nThese metrics will be examined in later Course 3 modules.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,8,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-3-01-lesson-09','cognizen-crypto-mastery-foundations-production','Maximum Drawdown and Trend-Following Checklist','cmf-module-3-01','text','### Maximum Drawdown\n\nMaximum drawdown is the largest decline from a previous portfolio peak to a later trough.\n\nA strategy may produce high returns while experiencing an unacceptable drawdown.\n\nThe investor must determine whether they can:\n\nFinancially survive it\n\nEmotionally continue\n\nMaintain the system\n\nAvoid forced liquidation\n\nHistorical drawdown may underestimate future drawdown.\n\n### Strategy Failure Versus Normal Drawdown\n\nA losing period does not automatically mean the strategy has failed.\n\nQuestions include:\n\nIs the drawdown within historical expectations?\n\nHas market structure changed permanently?\n\nAre costs higher?\n\nHas liquidity deteriorated?\n\nAre signals being executed correctly?\n\nIs the strategy overfitted?\n\nHas the market regime shifted?\n\nThe strategy should define conditions for review or suspension.\n\nAbandoning it after ordinary losses can lock in the worst period.\n\nContinuing blindly despite structural failure is equally dangerous.\n\n### Circuit Breakers\n\nA strategy may include circuit breakers such as:\n\nMaximum daily loss\n\nMaximum weekly loss\n\nMaximum portfolio drawdown\n\nMaximum number of consecutive losses\n\nExchange or data failure stop\n\nVolatility emergency rule\n\nA circuit breaker pauses new activity and triggers review.\n\nIt should not automatically lead to larger risk in an attempt to recover losses.\n\n### Trend-Following Decision Journal\n\nRecord:\n\nAsset\n\nTimeframe\n\nTrend definition\n\nEntry trigger\n\nStop\n\nPosition size\n\nPortfolio heat\n\nVolume\n\nVolatility\n\nBroader market regime\n\nExit rule\n\nActual result\n\nRule deviations\n\nThe journal helps distinguish:\n\nStrategy weakness\n\nExecution error\n\nEmotional interference\n\nNormal statistical variation\n\n### A Basic Trend-Following Framework\n\nThe following educational example is not a recommendation.\n\n### Market Universe\n\nOnly liquid digital assets meeting minimum volume and market-depth requirements.\n\n### Trend Filter\n\nLong positions considered only when:\n\nPrice is above a rising long-term moving average\n\nHigher-timeframe structure is bullish\n\n### Entry\n\nEnter after:\n\nBreakout above a recent high\n\nClosed-candle confirmation\n\nAcceptable relative volume\n\n### Initial Stop\n\nBelow:\n\nRecent structural low\n\nOr a volatility-adjusted distance\n\n### Position Size\n\nCalculated so that stop loss represents no more than the predefined risk allowance.\n\n### Exit\n\nClose when:\n\nPrice breaks a trailing structural low\n\nOr closes below a trailing trend indicator\n\n### Portfolio Limit\n\nTotal open risk and correlated exposure remain within defined limits.\n\nThis framework requires testing before use.\n\n### Example: Breakout Trend Trade\n\nSuppose:\n\nAsset price has consolidated between 90 and 100\n\nLong-term average is rising\n\nWeekly structure is bullish\n\nPrice closes above 100 on increased volume\n\nPlanned entry: 102\n\nStructural invalidation: 94\n\nRisk per token: 8\n\nMaximum capital risk: 800\n\nPosition quantity:\n\n800 ÷ 8 = 100 tokens\n\nPosition value:\n\n100 × 102 = 10,200 units\n\nThe strategy does not know how far price will rise.\n\nIt uses a trailing exit while limiting the initial loss.\n\n### Example: Pullback Trend Entry\n\nSuppose:\n\nDaily market is in an uptrend\n\nPrice breaks resistance at 200\n\nRises to 240\n\nPulls back toward 205\n\nForms a higher low\n\nBullish momentum returns\n\nEntry: 212\n\nInvalidation: 198\n\nRisk per token: 14\n\nMaximum capital risk: 700\n\nPosition quantity:\n\n700 ÷ 14 = 50 tokens\n\nThe pullback provides a closer structural risk level than entering at 240.\n\nThe trend can still fail.\n\n### Example: Whipsaw\n\nSuppose:\n\nPrice breaks a fifty-day high\n\nThe strategy enters\n\nPrice reverses and reaches the stop\n\nA one-unit loss is recorded\n\nPrice breaks out again one week later\n\nThe strategy re-enters\n\nThe second position develops into a major trend\n\nThe first loss was not necessarily an error.\n\nIt was the cost of responding to an unsuccessful signal.\n\nA participant who refuses to re-enter because of frustration may miss the trend the system was designed to capture.\n\n### Example: Trend Exit\n\nSuppose:\n\nEntry: 100\n\nPrice rises to 180\n\nTrailing stop moves to 155\n\nPrice reverses and exits at 154 after slippage\n\nThe strategy captures a substantial gain but does not sell at the top.\n\nThe participant may feel disappointed because the unrealised value was higher.\n\nTrend-following exits intentionally exchange perfect profit capture for the possibility of remaining in a larger trend.\n\n### Trend-Following Checklist\n\nBefore entering, ask:\n\nWhich timeframe defines the trend?\n\nIs the market forming higher highs and higher lows or lower highs and lower lows?\n\nIs the higher-timeframe trend aligned?\n\nIs the market trending or consolidating?\n\nWhat triggered the signal?\n\nIs the entry a breakout, pullback, retest or momentum entry?\n\nHas the candle closed?\n\nDoes volume support the move?\n\nIs volatility expanding or contracting?\n\nIs price excessively extended?\n\nWhat would invalidate the setup?\n\nWhere is the initial stop?\n\nWhat slippage may occur?\n\nHow large should the position be?\n\nWhat is the total portfolio heat?\n\nAre several positions expressing the same market view?\n\nIs leverage involved?\n\nWhat funding or borrowing costs apply?\n\nWhat trailing exit will be used?\n\nWill a fixed target interfere with the strategy’s positive skew?\n\nHow will the position be managed if it fails immediately?\n\nHow will it be managed if it becomes a large winner?\n\nHas the method been tested with realistic fees?\n\nAm I following a defined trend or chasing recent price movement?','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,9,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-3-01-lesson-10','cognizen-crypto-mastery-foundations-production','Common Trend-Following Mistakes and Key Takeaway','cmf-module-3-01','text','### Common Trend-Following Mistakes\n\n\n\n### Predicting Instead of Reacting\n\nThe participant enters before the trend criteria are met.\n\n### Chasing an Extended Move\n\nA valid trend is entered at an unattractive risk level.\n\n### Taking Profits Too Early\n\nLarge winners are prevented from offsetting repeated small losses.\n\n### Moving Stops Farther Away\n\nA planned small loss becomes a large one.\n\n### Refusing to Re-Enter\n\nA previous whipsaw creates emotional resistance to the next valid signal.\n\n### Using Excessive Leverage\n\nOrdinary trend corrections cause liquidation.\n\n### Ignoring Correlation\n\nSeveral positions create one large market exposure.\n\n### Changing Rules After Every Loss\n\nNormal statistical variation is treated as strategy failure.\n\n### Overfitting Parameters\n\nHistorical performance does not survive new conditions.\n\n### Ignoring Costs\n\nFrequent false signals make the strategy unprofitable after fees and slippage.\n\n### Using Trend Signals in Illiquid Markets\n\nPrice movement is easily manipulated and exits are unreliable.\n\n### Confusing a Bullish Trend With Fundamental Value\n\nA speculative asset can trend upward without sustainable value.\n\n### Common Misunderstandings\n\n#### “Trend Following Predicts Which Asset Will Rise”\n\nIt responds after directional evidence develops.\n\n#### “A Trend-Following Strategy Buys at the Bottom”\n\nIt usually enters after price has already begun moving.\n\n#### “A Good Trend Follower Wins Most Trades”\n\nMany systems lose frequently and depend on a smaller number of large winners.\n\n#### “A Moving-Average Crossover Guarantees a New Trend”\n\nSideways markets produce repeated false crossovers.\n\n#### “Overbought Means the Trend Must End”\n\nStrong trends can remain overbought for extended periods.\n\n#### “A Trailing Stop Locks In the Highest Profit”\n\nIt usually exits after some profit has been surrendered.\n\n#### “A Low Win Rate Means the System Is Bad”\n\nPayoff ratio and expectancy must also be considered.\n\n#### “More Filters Always Improve a Strategy”\n\nFilters may reduce false signals while delaying or eliminating profitable entries.\n\n#### “Trend Following Works in Every Market”\n\nIt generally performs poorly during choppy or range-bound periods.\n\n#### “A Backtest Proves the Strategy Will Remain Profitable”\n\nHistorical results can contain bias, overfitting and conditions that will not repeat.\n\n#### “Systematic Trading Removes All Emotion”\n\nRules help, but the participant must still tolerate losses, drawdowns and missed opportunities.\n\n#### “Several Crypto Trends Provide Diversification”\n\nThey may all depend on the same broad market movement.\n\n### Module Summary\n\nTrend following attempts to participate in sustained directional price movement without predicting the exact beginning or end.\n\nIt is reactive.\n\nThe strategy waits for evidence such as:\n\nHigher highs and higher lows\n\nLower highs and lower lows\n\nBreakouts\n\nPullback continuation\n\nMoving-average alignment\n\nMomentum\n\nVolume\n\nVolatility expansion\n\nTrend-following entries may use:\n\nBreakouts\n\nPullbacks\n\nRetests\n\nMomentum confirmation\n\nPrice channels\n\nMoving-average systems\n\nExits may use:\n\nStructural trailing stops\n\nMoving averages\n\nATR\n\nPrice channels\n\nTime-based rules\n\nTrend-following strategies often experience:\n\nMany small losses\n\nRepeated whipsaws\n\nA relatively low win rate\n\nA small number of large profitable positions\n\nThis positive-skew structure requires discipline.\n\nTaking profits too early or allowing losses to expand can destroy the strategy’s expected value.\n\nPosition sizing should reflect:\n\nStop distance\n\nVolatility\n\nLiquidity\n\nCorrelation\n\nTotal portfolio heat\n\nTrend following performs best during persistent directional markets and poorly during sideways conditions.\n\nFilters may reduce some false signals, but they also delay entries and can cause missed trends.\n\nA strategy should be tested using:\n\nRealistic fees\n\nSlippage\n\nOut-of-sample data\n\nFailed and delisted assets\n\nSeveral market cycles\n\nTrend following is not profitable simply because it is simple.\n\nIts potential value comes from disciplined execution, controlled losses and the willingness to remain in the occasional trend that travels much farther than expected.\n\n### Key Takeaway\n\nTrend following does not require you to predict where a market will begin or end.\n\nIt requires you to recognise directional evidence, define where that evidence fails and limit the amount lost when the signal is wrong.\n\nMost signals may produce little value.\n\nThe strategy depends on protecting capital through those failures so that you remain able to participate when a genuine trend develops.\n\nThe next module is 3.2: Mean-Reversion Strategy.','markdown',NULL,NULL,NULL,5,0,0,0,'',NULL,10,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-3-01-lesson-11','cognizen-crypto-mastery-foundations-production','Check your understanding','cmf-module-3-01','text','### Check your understanding\n\nAnswer these questions to self-assess your understanding before moving on.\n\n1. What is trend following?\n\n2. How does trend following differ from forecasting?\n\n3. Why are trend-following entries usually delayed?\n\n4. What commonly defines an uptrend?\n\n5. What commonly defines a downtrend?\n\n6. Why can several trends exist simultaneously?\n\n7. What is a pullback entry?\n\n8. What is a breakout entry?\n\n9. What evidence may support a genuine breakout?\n\n10. How does a retest entry work?\n\n11. Why is trend following different from chasing price?\n\n12. How can moving averages help identify trends?\n\n13. What is a dual moving-average crossover?\n\n14. Why do crossover systems perform poorly in sideways markets?\n\n15. What is a Donchian channel?\n\n16. What does ADX attempt to measure?\n\n17. Why should RSI overbought readings not automatically trigger an exit?\n\n18. How can volume support a trend analysis?\n\n19. What is a volatility-adjusted stop?\n\n20. How can ATR assist position sizing?\n\n21. What is a trailing stop?\n\n22. How does a structural trailing exit work?\n\n23. Why may fixed profit targets weaken a trend-following strategy?\n\n24. What is positive skew?\n\n25. How can a strategy with a low win rate remain profitable?\n\n26. What is the payoff ratio?\n\n27. What is expectancy?\n\n28. Why must trend followers prepare for losing streaks?\n\n29. What is a whipsaw?\n\n30. How can filters reduce whipsaws?\n\n31. What trade-offs do additional filters create?\n\n32. How does long-only trend following differ from long-and-short trend following?\n\n33. What risks arise when derivatives are used?\n\n34. How can funding rates affect a correct trend position?\n\n35. What is portfolio heat?\n\n36. Why should correlated positions be combined when measuring risk?\n\n37. What is pyramiding?\n\n38. Why is adding to losing positions dangerous?\n\n39. What is systematic trend following?\n\n40. How does discretionary trend following differ?\n\n41. What is overfitting?\n\n42. What is look-ahead bias?\n\n43. What is survivorship bias?\n\n44. Why should out-of-sample testing be used?\n\n45. What does maximum drawdown measure?\n\n46. How can a participant distinguish normal drawdown from possible strategy failure?\n\n47. What should be included in a trend-following decision journal?\n\n48. Why does a valid trend not necessarily provide a good entry?\n\n49. Why should a trend strategy be tested after fees and slippage?\n\n50. What makes consistent execution central to trend following?','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,11,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `course_sections` (`id`,`course_id`,`title`,`position`,`created_at`) SELECT 'cmf-module-3-02','cognizen-crypto-mastery-foundations-production','Module 3.2: .  Mean-Reversion Strategy',3,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
