INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-3-08-lesson-01','cognizen-crypto-mastery-foundations-production','What Is an Option? and Call Options','cmf-module-3-08','text','### Learning Objectives\n\nBy the end of this module, you should understand how cryptocurrency options create the right—but not always the obligation—to buy or sell an underlying asset at a specified price.\n\nYou should be able to distinguish calls from puts, option buyers from option sellers, and strike prices from expiry dates. You should also understand premium, moneyness, intrinsic value, time value, break-even prices and the basic payoff profiles of long and short options.\n\nThe module will introduce implied volatility and the main option Greeks, explain how options can be used for speculation, hedging and income strategies, and show why limited-risk option positions can still produce frequent or substantial losses.\n\n### Introduction\n\nFutures contracts create direct exposure to price movements.\n\nA long futures position generally gains as the underlying asset rises and loses as it falls. A short position behaves in the opposite way.\n\nOptions add another dimension.\n\nThey allow a participant to structure exposure around:\n\nDirection\n\nVolatility\n\nTime\n\nProbability\n\nMaximum loss\n\nSpecific price levels\n\nAn investor may use an option to protect a cryptocurrency portfolio from a severe decline. A trader may use an option to speculate on a large upward movement while limiting the maximum loss to the premium paid. Another participant may sell options to earn premium, accepting the obligation and potentially substantial risk that accompanies the position.\n\nOptions are flexible because their value does not depend only on whether the underlying asset rises or falls.\n\nAn option’s value can also change because:\n\nThe expected volatility of the asset changes\n\nTime passes\n\nThe asset moves closer to or farther from the strike price\n\nMarket liquidity changes\n\nAn important event approaches or passes\n\nThis flexibility makes options useful for sophisticated portfolio design.\n\nIt also makes them easy to misunderstand.\n\nA trader may correctly predict that Bitcoin will rise and still lose money on a call option because the rise was too small, occurred too late or was already reflected in an expensive premium.\n\nThe first objective in options education is therefore not to memorise complex strategies.\n\nIt is to understand the contract.\n\n### What Is an Option?\n\nAn option is a derivative contract that gives its buyer a defined right relating to an underlying asset.\n\nA call option gives the buyer the right to buy the underlying asset at a specified strike price.\n\nA put option gives the buyer the right to sell the underlying asset at a specified strike price.\n\nThe right exists until or at a specified expiry date, depending on the option’s exercise style.\n\nThe buyer pays a premium for this right.\n\nThe seller, also called the option writer, receives the premium and accepts the corresponding obligation if the option is exercised or settled in the buyer’s favour.\n\nOptions are asymmetric contracts.\n\nThe buyer has a right.\n\nThe seller carries an obligation.\n\nThis asymmetry is central to understanding option risk.\n\n### The Underlying Asset\n\nThe underlying asset is the market reference on which the option is based.\n\nIn digital asset markets, the underlying may be:\n\nBitcoin\n\nEther\n\nAnother cryptocurrency\n\nA cryptocurrency index\n\nA futures contract\n\nA volatility-related instrument\n\nAn option may settle financially without requiring actual delivery of the underlying cryptocurrency.\n\nFor example, a Bitcoin option may be settled in cash or cryptocurrency according to the difference between the strike and settlement price.\n\nThe participant must read the contract specification carefully.\n\nAn option referencing Bitcoin is not necessarily an option to receive Bitcoin into a self-custodial wallet.\n\n### Call Options\n\nA call option benefits its buyer when the underlying asset rises sufficiently.\n\nSuppose a trader buys a call option with a strike price of 60,000 units.\n\nThe option gives the trader the right to benefit as though buying the underlying asset at 60,000, subject to the contract’s settlement rules.\n\nIf the underlying settles below 60,000 at expiry, the right to buy at 60,000 has no economic value.\n\nIf the underlying settles at 70,000, the option has a value of approximately 10,000 units before accounting for the premium and contract multiplier.\n\nA call buyer is generally expressing a bullish view.\n\nA call seller accepts the risk that the underlying asset may rise above the strike.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,1,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-3-08-lesson-02','cognizen-crypto-mastery-foundations-production','Put Options and Contract Multiplier','cmf-module-3-08','text','### Put Options\n\nA put option benefits its buyer when the underlying asset falls sufficiently.\n\nSuppose an investor buys a put with a strike price of 50,000 units.\n\nThe put gives the investor the right to benefit as though selling the underlying at 50,000.\n\nIf the asset settles at 40,000, the option has approximately 10,000 units of intrinsic value before accounting for premium and contract size.\n\nIf the asset remains above 50,000 at expiry, the option may expire without value.\n\nA put buyer is generally expressing a bearish or protective view.\n\nA put seller accepts the obligation associated with a decline below the strike.\n\n### The Option Buyer\n\nThe option buyer pays the premium when entering the contract.\n\nFor an ordinary long call or long put, the premium is generally the maximum amount that can be lost, provided the position is not combined with borrowing or other exposures.\n\nThis defined maximum loss is one of the primary attractions of buying options.\n\nHowever, a limited loss does not mean a low probability of loss.\n\nAn option buyer can lose the full premium when:\n\nThe predicted movement does not occur\n\nThe movement is too small\n\nThe movement occurs after expiry\n\nImplied volatility declines\n\nTime decay reduces the option’s value\n\nOption buyers pay for flexibility and limited downside.\n\nThe cost of that flexibility is the premium.\n\n### The Option Seller\n\nThe option seller receives the premium.\n\nIn return, the seller accepts an obligation.\n\nA call seller may be required to compensate the buyer when the underlying rises above the strike.\n\nA put seller may be required to compensate the buyer when the underlying falls below the strike.\n\nThe seller’s profit may be limited to the premium received, while the potential loss can be much larger.\n\nAn uncovered call seller faces theoretically unlimited loss because the underlying asset can rise without a fixed maximum.\n\nA put seller can face a substantial loss if the underlying falls toward zero.\n\nOption selling should never be treated as effortless income.\n\nThe premium is compensation for accepting risk that may be infrequent but severe.\n\n### Strike Price\n\nThe strike price is the price at which the option’s contractual right is defined.\n\nA call with a 60,000 strike becomes economically valuable at expiry when the settlement price is above 60,000.\n\nA put with a 60,000 strike becomes economically valuable when the settlement price is below 60,000.\n\nDifferent strikes create different levels of:\n\nPremium\n\nProbability\n\nDirectional sensitivity\n\nMaximum payoff\n\nBreak-even price\n\nA strike closer to the current market price generally costs more than a distant strike, all else being equal, because it has a greater chance of finishing with value.\n\n### Expiry Date\n\nThe expiry date defines when the option contract ends.\n\nAt expiry, the option may:\n\nBe exercised\n\nBe settled automatically\n\nExpire without value\n\nConvert into the underlying or a financial payment\n\nOptions may expire over periods ranging from very short horizons to several months or years.\n\nA longer-dated option usually costs more because there is more time for a favourable movement to occur.\n\nTime is valuable to the buyer.\n\nAs expiry approaches, the amount of remaining time decreases.\n\nThis creates time decay.\n\n### Exercise Styles\n\nThe exercise style determines when the buyer may exercise the option.\n\n### European-Style Options\n\nA European-style option can generally be exercised only at expiry.\n\nIt may still be traded before expiry.\n\nThe word “European” refers to the exercise structure rather than the geographic location.\n\n### American-Style Options\n\nAn American-style option may generally be exercised at any time before expiry.\n\n### Other Exercise Structures\n\nSome contracts use different rules or automatic settlement.\n\nCryptocurrency option markets often use standardised exchange-defined settlement procedures.\n\nThe trader must verify the exact contract rather than assuming all options operate alike.\n\n### Physical and Cash Settlement\n\nAn option can settle through delivery or through a financial payment.\n\n### Physical Settlement\n\nThe underlying asset changes hands according to the contract.\n\n### Cash Settlement\n\nThe contract pays the difference between the strike and settlement price.\n\nA cryptocurrency option described as physically settled may deliver the relevant digital asset or a related contract, depending on platform rules.\n\nSettlement currency matters.\n\nA profitable option settled in a volatile cryptocurrency creates additional price exposure after settlement.\n\n### Contract Multiplier\n\nThe contract multiplier determines how much underlying exposure one option contract represents.\n\nOne contract might represent:\n\nOne Bitcoin\n\nA fraction of one Bitcoin\n\nA fixed currency value\n\nAnother defined quantity\n\nSuppose one option contract represents 0.1 Bitcoin.\n\nIf a call has intrinsic value of 5,000 units per Bitcoin, the contract’s intrinsic value is:\n\n5,000 × 0.1 = 500 units\n\nThe option quote alone does not reveal the total financial exposure.\n\nThe multiplier must be included.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,2,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-3-08-lesson-03','cognizen-crypto-mastery-foundations-production','Option Premium and Long Put Payoff','cmf-module-3-08','text','### Option Premium\n\nThe premium is the price paid by the option buyer and received by the seller.\n\nPremium is quoted according to the platform’s conventions.\n\nIt may be denominated in:\n\nNational currency\n\nStablecoin\n\nBitcoin\n\nEther\n\nAnother settlement asset\n\nThe total premium is commonly:\n\nQuoted premium × Contract multiplier × Number of contracts\n\nSuppose:\n\nCall premium: 2,000 units\n\nMultiplier: 0.1\n\nContracts: 5\n\nTotal premium:\n\n2,000 × 0.1 × 5 = 1,000 units\n\nThat 1,000-unit premium is the buyer’s initial cost and generally the maximum loss for the standalone long call.\n\n### Option Moneyness\n\nMoneyness describes the relationship between the strike price and the current underlying price.\n\nAn option may be:\n\nIn the money\n\nAt the money\n\nOut of the money\n\nThe meaning differs for calls and puts.\n\n### In-the-Money Call\n\nA call is in the money when the underlying price is above the strike.\n\nSuppose:\n\nUnderlying price: 65,000\n\nCall strike: 60,000\n\nThe call is 5,000 units in the money.\n\nIt has approximately 5,000 units of intrinsic value per underlying unit.\n\n### Out-of-the-Money Call\n\nA call is out of the money when the underlying price is below the strike.\n\nSuppose:\n\nUnderlying price: 55,000\n\nCall strike: 60,000\n\nExercising the right to buy at 60,000 would make no sense when the asset can be bought in the market at 55,000.\n\nThe call has no intrinsic value.\n\nIt may still have time value before expiry because price could rise.\n\n### In-the-Money Put\n\nA put is in the money when the underlying price is below the strike.\n\nSuppose:\n\nUnderlying price: 45,000\n\nPut strike: 50,000\n\nThe put has approximately 5,000 units of intrinsic value per underlying unit.\n\n### Out-of-the-Money Put\n\nA put is out of the money when the underlying price is above the strike.\n\nA put with a 50,000 strike has no intrinsic value when the asset trades at 55,000.\n\nIt may still have time value before expiry.\n\n### At-the-Money Options\n\nAn option is at the money when the strike is close to the current underlying price.\n\nAt-the-money options usually contain substantial time value and are highly sensitive to changes in price and implied volatility.\n\nBecause the strike and market price are close, relatively small movements can change the option’s moneyness.\n\n### Intrinsic Value\n\nIntrinsic value is the immediate exercise value of an option.\n\nFor a call:\n\nIntrinsic value = Maximum of zero or underlying price minus strike price\n\nFor a put:\n\nIntrinsic value = Maximum of zero or strike price minus underlying price\n\nSuppose:\n\nUnderlying price: 70\n\nCall strike: 60\n\nCall intrinsic value:\n\n70 − 60 = 10\n\nIf the call premium is 14, the remaining four units represent time or extrinsic value.\n\n### Extrinsic Value\n\nExtrinsic value is the portion of the option premium beyond intrinsic value.\n\nIt reflects factors such as:\n\nTime remaining\n\nExpected volatility\n\nInterest rates\n\nSupply and demand\n\nEvent risk\n\nLiquidity\n\nThe simplified relationship is:\n\nOption premium = Intrinsic value + Extrinsic value\n\nAn out-of-the-money option consists entirely of extrinsic value.\n\nAt expiry, extrinsic value generally becomes zero.\n\nOnly intrinsic value remains.\n\n### Time Value\n\nTime value reflects the possibility that the option may become more valuable before expiry.\n\nA six-month call usually has more time value than an otherwise identical one-week call.\n\nMore time allows more opportunity for the underlying asset to move beyond the strike.\n\nTime is valuable to the buyer and a source of potential income to the seller.\n\nHowever, time value does not decline at a constant rate.\n\nDecay often accelerates as expiry approaches, especially for at-the-money options.\n\n### Long Call Payoff\n\nA long call offers bullish exposure with a predefined maximum loss.\n\nSuppose:\n\nStrike: 100\n\nPremium: 8\n\nContract multiplier: 1\n\nAt expiry:\n\n| Underlying price | Call value | Net result |\n| --- | --- | --- |\n| 80 | 0 | −8 |\n| 100 | 0 | −8 |\n| 108 | 8 | 0 |\n| 120 | 20 | +12 |\n| 150 | 50 | +42 |\n\nThe maximum loss is the eight-unit premium.\n\nThe break-even price at expiry is:\n\nStrike + Premium = 100 + 8 = 108\n\nPotential profit is theoretically unlimited because the underlying can continue rising.\n\n### Long Put Payoff\n\nA long put provides bearish exposure or portfolio protection.\n\nSuppose:\n\nStrike: 100\n\nPremium: 7\n\nAt expiry:\n\n| Underlying price | Put value | Net result |\n| --- | --- | --- |\n| 120 | 0 | −7 |\n| 100 | 0 | −7 |\n| 93 | 7 | 0 |\n| 80 | 20 | +13 |\n| 50 | 50 | +43 |\n\nThe maximum loss is the seven-unit premium.\n\nThe break-even price is:\n\nStrike − Premium = 100 − 7 = 93\n\nThe maximum theoretical value occurs if the underlying falls to zero.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,3,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-3-08-lesson-04','cognizen-crypto-mastery-foundations-production','Short Call Payoff and Volatility Expansion','cmf-module-3-08','text','### Short Call Payoff\n\nA short call receives premium but accepts risk above the strike.\n\nSuppose:\n\nStrike: 100\n\nPremium received: 8\n\nIf the underlying remains at or below 100 at expiry, the option expires without intrinsic value and the seller keeps the premium.\n\nIf price rises to 130, the option’s intrinsic value is 30.\n\nThe seller’s net loss is:\n\n30 − 8 = 22 units\n\nAn uncovered short call has theoretically unlimited loss potential.\n\n### Short Put Payoff\n\nA short put receives premium and accepts the obligation associated with falling prices.\n\nSuppose:\n\nStrike: 100\n\nPremium received: 7\n\nIf the underlying remains above 100, the seller keeps seven units.\n\nIf price falls to 60, the option’s intrinsic value is 40.\n\nThe seller’s loss is:\n\n40 − 7 = 33 units\n\nIf the asset falls to zero, the maximum loss is approximately:\n\nStrike − Premium = 100 − 7 = 93 units\n\nThis can be substantial.\n\n### Break-Even Does Not Mean Early Profitability Is Impossible\n\nBreak-even calculations such as strike plus premium apply at expiry.\n\nBefore expiry, an option can be sold at a profit even when the underlying has not reached the expiry break-even price.\n\nThis can happen because:\n\nTime remains\n\nImplied volatility rises\n\nThe underlying moves favourably\n\nMarket demand increases\n\nSimilarly, an option can lose value before expiry even when the underlying moves in the expected direction.\n\nOptions should therefore not be analysed only through expiry payoff diagrams.\n\nTheir market value changes continuously.\n\n### The Options Chain\n\nAn options chain displays available contracts for a particular underlying asset.\n\nIt may show:\n\nStrike prices\n\nExpiry dates\n\nCall and put prices\n\nBid and ask\n\nTrading volume\n\nOpen interest\n\nImplied volatility\n\nGreeks\n\nA participant should examine the specific contract rather than saying only, “I am buying a Bitcoin option.”\n\nThe strike and expiry determine most of the position’s behaviour.\n\n### Option Bid-Ask Spreads\n\nOptions can have wider spreads than their underlying markets.\n\nSuppose an option has:\n\nBid: 5\n\nAsk: 7\n\nA buyer pays close to seven.\n\nAn immediate sale may receive close to five.\n\nThe position begins with a two-unit spread loss.\n\nWide spreads are common when:\n\nThe contract is far from the current price\n\nExpiry is distant\n\nOpen interest is low\n\nThe market is volatile\n\nFew market makers participate\n\nA technically attractive option can be economically unsuitable when liquidity is poor.\n\n### Option Volume and Open Interest\n\nOption volume measures how many contracts traded during a period.\n\nOpen interest measures how many contracts remain outstanding.\n\nHigh open interest may indicate a more established market.\n\nIt does not guarantee deep liquidity at the desired price.\n\nA contract may have high open interest and a wide spread.\n\nThe participant should examine both current quotes and available size.\n\n### Implied Volatility\n\nImplied volatility, or IV, is the level of expected future volatility reflected in the option’s market price.\n\nIt is called implied because it is derived from the premium using an option-pricing model.\n\nHigher implied volatility generally increases both call and put premiums, all else being equal.\n\nWhen the market expects large future movement, option buyers must pay more.\n\nWhen expected movement is lower, premiums generally decline.\n\nImplied volatility does not predict direction.\n\nIt reflects the market’s pricing of the size and uncertainty of future movement.\n\n### Realised Volatility\n\nRealised volatility measures how much the underlying asset actually moved over a historical period.\n\nImplied volatility looks forward through market pricing.\n\nRealised volatility looks backward through observed returns.\n\nAn option seller may profit when implied volatility is higher than the volatility that actually occurs, provided losses and hedging costs remain controlled.\n\nAn option buyer generally benefits when realised movement exceeds what was priced into the premium.\n\nThis relationship is simplified because timing, direction and dynamic hedging also matter.\n\n### Implied Versus Realised Volatility\n\nSuppose the option market prices an annualised implied volatility of eighty percent.\n\nIf the asset subsequently moves much less than expected, option premiums may prove expensive.\n\nIf the asset moves more than expected, options may prove relatively cheap.\n\nThe comparison is not straightforward because an annualised volatility number does not describe one expected price target.\n\nIt describes a distribution of possible movements under model assumptions.\n\nCryptocurrency returns frequently contain jumps and extreme events that challenge standard assumptions.\n\n### Volatility Expansion\n\nAn option buyer may benefit when implied volatility rises.\n\nThis can happen before:\n\nRegulatory decisions\n\nProtocol upgrades\n\nEconomic announcements\n\nCourt outcomes\n\nMajor token events\n\nExpected market stress\n\nThe option can increase in value even before the underlying moves substantially.\n\nThe buyer is paying for uncertainty.\n\nIf the expected event becomes more uncertain, the premium may rise.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,4,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-3-08-lesson-05','cognizen-crypto-mastery-foundations-production','Volatility Crush and Theta','cmf-module-3-08','text','### Volatility Crush\n\nA volatility crush occurs when implied volatility falls sharply.\n\nThis often happens after an anticipated event passes.\n\nBefore the event, traders pay high premiums because a large movement is possible.\n\nAfter the event, uncertainty decreases.\n\nEven if the underlying moves in the expected direction, the option may lose value because the decline in implied volatility outweighs the directional gain.\n\nThis is why buying a call before positive news does not guarantee profit when the news arrives.\n\nThe market may already have priced in the event and an expensive level of volatility.\n\n### Implied Volatility Rank and Percentile\n\nTraders may compare current implied volatility with its own historical range.\n\nAn implied volatility rank may indicate where current IV lies between its historical minimum and maximum.\n\nAn implied volatility percentile may indicate the proportion of historical observations below the current reading.\n\nThese measures can help identify whether options appear relatively expensive or inexpensive compared with recent history.\n\nThey do not prove that volatility will revert.\n\nA new market regime can justify higher or lower volatility than the past.\n\n### Volatility Smile and Skew\n\nOptions with different strikes often trade at different implied volatilities.\n\nIf all strikes used the same volatility, the curve would be flat.\n\nIn practice, the curve may form a smile or skew.\n\nA volatility skew can reflect:\n\nGreater demand for downside protection\n\nSpeculative demand for upside calls\n\nFear of crashes\n\nSupply from option sellers\n\nMarket-maker inventory\n\nTail-risk pricing\n\nIn cryptocurrency markets, both downside puts and far-upside calls can receive unusual demand under different conditions.\n\nThe shape of the volatility curve provides information about how the market prices asymmetric risks.\n\n### Put Skew\n\nPut skew occurs when downside puts trade at higher implied volatility than comparable calls or at-the-money options.\n\nThis may reflect demand for crash protection.\n\nA steep put skew makes protective puts expensive.\n\nIt can also increase the premium available to put sellers, who accept significant downside risk.\n\nExpensive protection is not proof that a decline will occur.\n\nIt means the market is charging more for that protection.\n\n### Call Skew\n\nCall skew may develop when traders aggressively seek upside exposure.\n\nThis can occur during speculative markets or ahead of a possible positive catalyst.\n\nFar-out-of-the-money calls may trade at high implied volatility because many participants want leveraged upside with defined premium risk.\n\nHigh demand can make the options expensive even if the probability of reaching the strike remains low.\n\n### Volatility Term Structure\n\nThe volatility term structure compares implied volatility across expiry dates.\n\nShort-term options may have higher IV when an immediate event is expected.\n\nLonger-term options may have higher IV when uncertainty is persistent.\n\nAn inverted term structure may appear during acute market stress, with near-term volatility priced above longer-term volatility.\n\nThe term structure can affect:\n\nOption selection\n\nCalendar spreads\n\nRoll costs\n\nEvent strategies\n\nA trader should not compare premiums across expiries without adjusting for time and implied volatility.\n\n### Delta\n\nDelta estimates how much an option’s price may change for a small change in the underlying asset, assuming other factors remain constant.\n\nA call delta generally ranges between zero and one.\n\nA put delta generally ranges between zero and negative one.\n\nSuppose a call has a delta of 0.50.\n\nA one-unit increase in the underlying may increase the option by approximately 0.50 units, before accounting for changes in other factors.\n\nDelta also represents the option’s approximate directional exposure.\n\nOne call with a 0.50 delta and a multiplier of one behaves initially like approximately half a unit of the underlying.\n\nDelta changes as the underlying moves and time passes.\n\n### Gamma\n\nGamma measures how quickly delta changes as the underlying price moves.\n\nGamma is generally highest for near-expiry options close to the current market price.\n\nA high-gamma option can change directional sensitivity very rapidly.\n\nFor an option buyer, positive gamma can create accelerating gains when the market moves strongly.\n\nFor an option seller, negative gamma can create rapidly increasing losses.\n\nGamma helps explain why short-dated option positions can become unstable near expiry.\n\n### Theta\n\nTheta estimates the effect of time passing on an option’s value, assuming other factors remain constant.\n\nLong options generally have negative theta.\n\nAs time passes, the option loses some extrinsic value.\n\nShort options generally have positive theta because the seller benefits from the decay of the option sold.\n\nTheta is not free income.\n\nOption sellers earn time decay while accepting volatility and tail risk.\n\nTime decay often accelerates as expiry approaches, particularly for at-the-money options.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,5,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-3-08-lesson-06','cognizen-crypto-mastery-foundations-production','Vega and Protective Put Example','cmf-module-3-08','text','### Vega\n\nVega estimates how much an option’s value may change when implied volatility changes.\n\nLong calls and long puts generally have positive vega.\n\nThey benefit when implied volatility rises, all else being equal.\n\nShort options generally have negative vega.\n\nThey can lose when implied volatility rises.\n\nLonger-dated options usually have greater vega sensitivity than very short-dated options.\n\n### Rho\n\nRho estimates sensitivity to interest rates.\n\nIn short-dated cryptocurrency options, rho may be less influential than delta, gamma, theta and vega.\n\nIt can become more relevant for longer-dated contracts and when financing conditions change materially.\n\nCryptocurrency-specific funding, collateral and stablecoin conditions may also affect option pricing in ways not captured fully by traditional interest-rate assumptions.\n\n### The Greeks Are Estimates\n\nThe Greeks are produced by pricing models.\n\nThey are not fixed contractual guarantees.\n\nThey change as:\n\nUnderlying price changes\n\nTime passes\n\nImplied volatility changes\n\nInterest rates change\n\nMarket conditions shift\n\nDuring sharp market movement, several Greeks change simultaneously.\n\nA trader should use them as risk measures, not exact predictions of the option’s future price.\n\n### Delta as Approximate Probability\n\nSome participants interpret an option’s absolute delta as a rough estimate of the probability that it will finish in the money.\n\nFor example, a call with a delta of 0.30 may be loosely interpreted as having an approximately thirty-percent probability of expiring in the money under certain model assumptions.\n\nThis is only an approximation.\n\nDelta is not a direct objective probability.\n\nThe estimate depends on:\n\nPricing model\n\nVolatility assumptions\n\nMarket risk pricing\n\nDistribution assumptions\n\nFinishing in the money also does not guarantee profitability because the premium must be recovered.\n\n### Long Call Strategy\n\nA long call is appropriate when the participant expects a sufficiently large upward movement.\n\nIts advantages include a defined maximum loss and potentially large upside.\n\nIts challenges include:\n\nPremium cost\n\nTime decay\n\nVolatility crush\n\nNeed for sufficient movement\n\nExpiry selection\n\nA call can be a more controlled alternative to a leveraged futures long because it cannot normally be liquidated beyond the premium paid.\n\nHowever, frequent full-premium losses can still damage the portfolio.\n\n### Selecting a Call Strike\n\nAn in-the-money call costs more but has greater intrinsic value and higher delta.\n\nAn at-the-money call provides balanced directional sensitivity and time value.\n\nAn out-of-the-money call is cheaper but requires a larger movement before becoming profitable at expiry.\n\nCheap options are not necessarily good value.\n\nA very distant call may have a low probability of producing any payoff.\n\nThe participant should select the strike according to the expected movement, time horizon and acceptable premium loss.\n\n### Selecting an Expiry\n\nA short-dated call is cheaper but gives the market less time to move.\n\nIt also experiences faster time decay.\n\nA longer-dated call costs more but provides greater time flexibility and usually greater sensitivity to implied volatility.\n\nThe expiry should allow enough time for the investment thesis to develop.\n\nBuying a one-week option for a thesis expected to unfold over three months creates a mismatch between analysis and instrument.\n\n### Long Put Strategy\n\nA long put may be used for bearish speculation or portfolio insurance.\n\nFor speculation, the trader expects a significant decline.\n\nFor protection, the investor owns the underlying asset and buys a put to limit downside below the strike.\n\nThe premium is the cost of the protection.\n\nIf the asset rises, the put may expire without value, but the underlying position benefits.\n\nThe loss of premium should be evaluated like an insurance cost rather than automatically described as a failed investment.\n\n### Protective Put\n\nA protective put combines:\n\nLong underlying asset\n\nLong put option\n\nSuppose an investor owns Bitcoin at 60,000 and buys a 50,000-strike put.\n\nIf Bitcoin falls far below 50,000, gains on the put offset part of the loss in the underlying.\n\nThe investor retains upside if Bitcoin rises, less the premium paid.\n\nThe protective put creates a temporary floor, subject to:\n\nStrike\n\nPremium\n\nExpiry\n\nContract multiplier\n\nBasis\n\nSettlement\n\nProtection ends when the option expires.\n\n### Protective Put Example\n\nSuppose:\n\nOne Bitcoin owned at 60,000\n\nOne put with strike 50,000\n\nPremium 2,000\n\nContract covers one Bitcoin\n\nAt expiry, if Bitcoin falls to 35,000:\n\nUnderlying loss:\n\n35,000 − 60,000 = −25,000\n\nPut value:\n\n50,000 − 35,000 = 15,000\n\nNet result before other costs:\n\n−25,000 + 15,000 − 2,000 premium = −12,000\n\nThe loss remains substantial, but the put improves the outcome relative to holding the unprotected Bitcoin.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,6,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-3-08-lesson-07','cognizen-crypto-mastery-foundations-production','Covered Call and Long Straddle Example','cmf-module-3-08','text','### Covered Call\n\nA covered call combines:\n\nLong underlying asset\n\nShort call option\n\nThe investor receives premium in exchange for limiting some upside.\n\nSuppose an investor owns one Bitcoin at 60,000 and sells a call with a 70,000 strike for a 2,000 premium.\n\nIf Bitcoin remains below 70,000 at expiry, the investor keeps the premium.\n\nIf Bitcoin rises well above 70,000, the short call offsets gains beyond the strike according to the settlement rules.\n\nThe covered call is not risk-free.\n\nThe underlying asset can still fall sharply.\n\nThe premium provides only limited downside protection.\n\n### Covered Call Economic Effect\n\nA covered call exchanges uncertain upside for immediate premium.\n\nIt may be appropriate when the investor expects:\n\nModerate price movement\n\nSideways conditions\n\nWillingness to sell or cap exposure near the strike\n\nIt may be inappropriate when the investor expects a major breakout.\n\nA strong rally can create substantial opportunity cost because gains above the strike are limited.\n\nSelling the call should be viewed as a conditional commitment, not free additional income.\n\n### Cash-Secured Put\n\nA cash-secured put involves selling a put while maintaining enough cash or stable collateral to purchase the underlying at the strike.\n\nSuppose an investor is willing to buy an asset at 50,000.\n\nThey sell a 50,000-strike put and receive premium.\n\nIf the asset remains above the strike, the put may expire without value and the seller keeps the premium.\n\nIf it falls below the strike, the seller may effectively acquire exposure near 50,000, adjusted for the premium.\n\nThe strategy still carries substantial downside risk if the asset collapses.\n\nBeing willing to buy at 50,000 does not mean the asset remains attractive after new negative information emerges.\n\n### Effective Purchase Price\n\nFor a cash-secured put, the approximate effective purchase price is:\n\nStrike − Premium received\n\nSuppose:\n\nStrike: 50,000\n\nPremium: 3,000\n\nEffective price:\n\n50,000 − 3,000 = 47,000\n\nIf the asset falls to 20,000, the effective price of 47,000 does not protect the seller from a major loss.\n\nPremium reduces the cost basis.\n\nIt does not create a guaranteed bargain.\n\n### Collar Strategy\n\nA collar combines:\n\nLong underlying asset\n\nLong protective put\n\nShort call\n\nThe put limits downside.\n\nThe short call helps finance the put but limits upside.\n\nSuppose an investor owns an asset at 100, buys a put at 85 and sells a call at 120.\n\nThe portfolio is protected below approximately 85, subject to premiums, while gains above approximately 120 are capped.\n\nA collar can be useful when the investor wants to preserve a position but reduce short-term uncertainty.\n\n### Bull Call Spread\n\nA bull call spread combines:\n\nLong call at a lower strike\n\nShort call at a higher strike\n\nSame expiry\n\nThe short call reduces the premium cost.\n\nIt also limits maximum profit.\n\nSuppose:\n\nBuy 100-strike call for 10\n\nSell 120-strike call for 4\n\nNet premium:\n\n10 − 4 = 6\n\nMaximum value of the spread at expiry:\n\n120 − 100 = 20\n\nMaximum profit:\n\n20 − 6 = 14\n\nMaximum loss is the six-unit net premium.\n\nThe spread is suitable when the participant expects a moderate rise rather than unlimited upside.\n\n### Bear Put Spread\n\nA bear put spread combines:\n\nLong put at a higher strike\n\nShort put at a lower strike\n\nSame expiry\n\nThe short put reduces the premium cost and limits the maximum profit.\n\nSuppose:\n\nBuy 100-strike put for 9\n\nSell 80-strike put for 3\n\nNet premium:\n\n9 − 3 = 6\n\nMaximum spread value:\n\n100 − 80 = 20\n\nMaximum profit:\n\n20 − 6 = 14\n\nMaximum loss is six.\n\nThe strategy expresses a defined-risk bearish view.\n\n### Vertical Spreads\n\nBull call spreads and bear put spreads are examples of vertical spreads.\n\nThe options have the same expiry but different strikes.\n\nVertical spreads can reduce:\n\nPremium cost\n\nTime-decay exposure\n\nImplied-volatility sensitivity\n\nThey also cap potential profit.\n\nA spread should be evaluated as one combined position.\n\nManaging only one leg can create unexpected naked-option exposure.\n\n### Long Straddle\n\nA long straddle combines:\n\nLong call\n\nLong put\n\nSame strike\n\nSame expiry\n\nThe strategy benefits from a large movement in either direction.\n\nIt is appropriate when the participant expects substantial volatility but is uncertain about direction.\n\nThe disadvantage is that two premiums are paid.\n\nThe underlying must move sufficiently to overcome both premiums.\n\nA small or delayed movement can cause both options to lose value.\n\n### Long Straddle Example\n\nSuppose:\n\nStrike: 100\n\nCall premium: 8\n\nPut premium: 7\n\nTotal premium: 15\n\nUpper break-even at expiry:\n\n100 + 15 = 115\n\nLower break-even:\n\n100 − 15 = 85\n\nThe strategy profits beyond either break-even.\n\nIf the underlying remains near 100, both options may expire without intrinsic value and the full fifteen-unit premium is lost.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,7,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-3-08-lesson-08','cognizen-crypto-mastery-foundations-production','Long Strangle and Tail-Risk Hedging','cmf-module-3-08','text','### Long Strangle\n\nA long strangle uses:\n\nOut-of-the-money call\n\nOut-of-the-money put\n\nSame expiry\n\nIt usually costs less than a straddle.\n\nIt requires a larger movement to become profitable.\n\nFor example, the participant might buy an 110 call and a 90 put while the asset trades near 100.\n\nThe trade can benefit from a major breakout or breakdown.\n\nIt may lose the complete combined premium if price remains between the strikes.\n\n### Short Straddle and Short Strangle\n\nSelling a straddle or strangle earns premium when the underlying remains within a limited range and implied volatility falls.\n\nThe seller is short volatility and time value.\n\nThe risk can be extreme.\n\nA short straddle has substantial downside risk and theoretically unlimited upside risk.\n\nA short strangle has wider break-even points but can still suffer very large losses during a strong move.\n\nHigh historical win rates can conceal rare, destructive losses.\n\nThese strategies require advanced margin and risk management.\n\n### Long Volatility Versus Short Volatility\n\nA long option position is generally long volatility.\n\nIt benefits when the underlying moves more than expected or when implied volatility rises.\n\nA short option position is generally short volatility.\n\nIt benefits when movement is smaller than expected and option value decays.\n\nDirectional exposure still matters.\n\nA long call is both bullish and long volatility.\n\nA long straddle aims to reduce directional preference while remaining long volatility.\n\nA covered call is long the asset but short some upside volatility.\n\n### Event Trading\n\nOptions are often used around events because they allow predefined-risk exposure to large movement.\n\nHowever, event premiums can become very expensive.\n\nThe market may already expect a substantial move.\n\nThe relevant question is not merely:\n\n“Will the asset move?”\n\nIt is:\n\n“Will the asset move more than the option market has already priced?”\n\nA large movement can occur and still disappoint an option buyer if the move is smaller than expected.\n\n### Expected Move\n\nOption markets can be used to estimate a rough expected movement over a period.\n\nOne common approximation uses the cost of an at-the-money straddle.\n\nSuppose the underlying trades at 100 and the at-the-money straddle costs 12.\n\nThe market is pricing a substantial movement, approximately around twelve units in either direction under simplified assumptions.\n\nThis is not a guaranteed range or direct probability forecast.\n\nIt is a market-implied cost of volatility.\n\n### Implied Movement Is Not Directional\n\nAn expensive straddle does not indicate whether price will rise or fall.\n\nIt indicates that option buyers and sellers have agreed on a relatively high price for future uncertainty.\n\nDirectional analysis must come from other evidence.\n\nA trader who buys only the call side of an expensive event market must be correct about both direction and magnitude.\n\n### Hedging a Cryptocurrency Portfolio\n\nOptions can protect a broader portfolio without forcing the investor to sell the underlying assets.\n\nPossible hedges include:\n\nBuying puts on the same asset\n\nBuying puts on a related benchmark\n\nCreating a collar\n\nBuying a broad-market downside option\n\nThe hedge ratio should reflect the portfolio’s sensitivity to the underlying option.\n\nA portfolio of smaller tokens may not be fully protected by Bitcoin puts because altcoins can decline more sharply or behave differently.\n\nThis creates cross-hedge and basis risk.\n\n### Hedge Cost\n\nProtection has a cost.\n\nRepeatedly buying puts can reduce long-term portfolio return if the protection expires unused.\n\nThe investor should decide:\n\nWhich risks require protection\n\nHow much downside should be covered\n\nWhich strike is appropriate\n\nHow long the protection should last\n\nWhether premium cost is sustainable\n\nInsurance that is too expensive can damage the portfolio even when no crisis occurs.\n\nInsurance that is too limited may provide little value during a severe decline.\n\n### Rolling Protection\n\nA protective option eventually expires.\n\nMaintaining ongoing protection requires buying a new option or rolling the existing position.\n\nRoll cost depends on:\n\nRemaining time value\n\nNew implied volatility\n\nStrike\n\nMarket price\n\nSpread\n\nLiquidity\n\nProtection may become most expensive precisely when market fear is highest.\n\nA hedging programme should be planned before the crisis rather than improvised after volatility has surged.\n\n### Tail-Risk Hedging\n\nTail-risk hedging seeks protection against rare, severe market declines.\n\nIt may use far-out-of-the-money puts.\n\nThese options can be relatively cheap under normal conditions but frequently expire without value.\n\nA genuine crash can produce a large payoff.\n\nThe strategy resembles insurance against low-frequency, high-impact events.\n\nThe participant must accept repeated premium losses and avoid increasing the hedge cost beyond a sustainable level.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,8,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-3-08-lesson-09','cognizen-crypto-mastery-foundations-production','Options for Position Replacement and Early Exercise and Assignment','cmf-module-3-08','text','### Options for Position Replacement\n\nAn investor may replace part of a spot position with call options.\n\nFor example, instead of holding an asset worth 50,000 units, the investor may sell the spot position and buy calls costing 5,000.\n\nThis reduces the maximum capital directly at risk to the premium.\n\nIt also introduces:\n\nExpiry\n\nTime decay\n\nImplied-volatility risk\n\nIncomplete delta exposure\n\nIf the asset rises modestly or slowly, the calls may underperform the original spot position.\n\nCapital efficiency is not the same as economic equivalence.\n\n### Synthetic Positions\n\nOptions can be combined to create exposures resembling other instruments.\n\nA synthetic long position can be approximated by:\n\nLong call\n\nShort put\n\nSame strike and expiry\n\nA synthetic short uses:\n\nLong put\n\nShort call\n\nSame strike and expiry\n\nThese combinations can behave similarly to futures exposure.\n\nThey may also involve:\n\nMargin\n\nAssignment\n\nDifferent liquidity\n\nPremium and interest effects\n\nSynthetic positions should not be used without understanding both option legs.\n\n### Delta Hedging\n\nDelta hedging adjusts exposure to reduce the directional sensitivity of an option position.\n\nSuppose a trader owns calls with a combined delta equivalent to 0.5 Bitcoin.\n\nThey may short approximately 0.5 Bitcoin through spot or futures to reduce net directional exposure.\n\nAs price changes, the option delta changes.\n\nThe hedge must be adjusted.\n\nThis is dynamic hedging.\n\nFrequent adjustment creates:\n\nFees\n\nSlippage\n\nFunding\n\nExecution risk\n\nDelta neutrality is temporary.\n\n### Gamma Trading\n\nAn option buyer with positive gamma may benefit from large back-and-forth movements when dynamically hedging.\n\nAs the asset rises, the option delta increases and the trader may sell some underlying exposure.\n\nAs it falls, delta decreases and the trader may buy some exposure back.\n\nThis resembles buying low and selling high around the hedge.\n\nThe strategy works only if realised movement is sufficient to overcome:\n\nOption premium\n\nTime decay\n\nTransaction costs\n\nGamma trading is advanced and operationally demanding.\n\n### Theta Versus Gamma\n\nOption buyers typically own positive gamma and pay theta.\n\nThey benefit from movement but lose value as time passes.\n\nOption sellers typically receive theta and carry negative gamma.\n\nThey benefit from calm markets but can lose rapidly during large movement.\n\nThis trade-off is central to option pricing.\n\nThere is no free combination of steady time income and unlimited safety.\n\nPremium exists because the seller accepts convex risk.\n\n### Convexity\n\nConvexity describes how an option’s payoff can accelerate as the underlying moves favourably.\n\nA long call may lose only the premium if price falls, while gains increase as price rises.\n\nA long put behaves similarly during a decline.\n\nThis asymmetric payoff is valuable during extreme movement.\n\nThe buyer pays for convexity through premium and time decay.\n\nThe seller earns premium while accepting the opposite exposure.\n\n### Option Seller Margin\n\nOption sellers must post collateral or margin.\n\nThe required amount depends on:\n\nStrike\n\nExpiry\n\nUnderlying volatility\n\nWhether the position is covered\n\nOther portfolio positions\n\nPlatform rules\n\nMargin requirements may rise during volatility.\n\nA position that appeared sufficiently collateralised can face a margin call or liquidation after:\n\nUnderlying price movement\n\nImplied-volatility increase\n\nCorrelation change\n\nPlatform rule adjustment\n\nOption sellers should not assume the initial margin requirement defines the maximum possible loss.\n\n### Naked Options\n\nA naked option is sold without a corresponding underlying position or protective option that limits the risk.\n\nAn uncovered short call is especially dangerous because its loss is theoretically unlimited.\n\nA naked short put carries loss approaching the strike value if the underlying falls to zero.\n\nThe premium received is usually small relative to the capital at risk.\n\nNaked option selling is unsuitable for participants who do not fully understand margin, volatility and tail risk.\n\n### Covered Versus Defined-Risk Selling\n\nA covered call has the underlying asset available to offset the call obligation.\n\nA cash-secured put maintains sufficient capital to accept downside exposure.\n\nA vertical credit spread uses a purchased option to cap the seller’s maximum loss.\n\nThese structures do not eliminate risk.\n\nThey define or support the obligation more clearly than an uncovered position.\n\nA strategy should always distinguish between:\n\nCovered\n\nCash secured\n\nDefined risk\n\nNaked\n\n### Early Exercise and Assignment\n\nFor options permitting early exercise, the seller may be assigned before expiry.\n\nAssignment means the seller must fulfil the option obligation.\n\nEarly assignment may be influenced by:\n\nDeep intrinsic value\n\nRemaining time value\n\nInterest rates\n\nSettlement benefits\n\nPlatform rules\n\nEuropean-style options usually avoid early assignment because exercise occurs only at expiry.\n\nThe participant should know whether the platform settles automatically or requires action.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,9,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-3-08-lesson-10','cognizen-crypto-mastery-foundations-production','Automatic Exercise and Premium-at-Risk Model','cmf-module-3-08','text','### Automatic Exercise\n\nAn exchange may automatically exercise or settle options that finish in the money.\n\nThresholds and procedures vary.\n\nThe trader should verify:\n\nMinimum in-the-money amount\n\nSettlement price\n\nSettlement currency\n\nExercise fees\n\nWhether manual instructions are required\n\nAn option that appears profitable can produce an unexpected position or settlement if the trader does not understand expiry procedures.\n\n### Pin Risk\n\nPin risk occurs when the underlying trades close to the strike near expiry.\n\nSmall price changes can determine whether the option finishes in or out of the money.\n\nThe trader may face uncertainty about:\n\nExercise\n\nAssignment\n\nFinal delta\n\nHedge requirements\n\nShort-dated at-the-money options can change sensitivity rapidly because gamma is high near expiry.\n\nPositions should not be left unmanaged solely because the apparent remaining premium is small.\n\n### Expiry-Day Risk\n\nAs expiry approaches:\n\nTime value collapses\n\nGamma may increase near the strike\n\nLiquidity may shift\n\nSpreads may widen\n\nPosition sensitivity may change rapidly\n\nAn option can move from nearly worthless to valuable—or the reverse—after a relatively small underlying movement.\n\nTraders should understand the exact expiry time and settlement method.\n\nCryptocurrency markets continue trading outside many traditional market hours, but the option contract still uses a defined settlement window.\n\n### Option Liquidity Risk\n\nA profitable option position may be difficult to close if the contract is illiquid.\n\nThe participant may face:\n\nWide spreads\n\nSmall order sizes\n\nPrice gaps\n\nLimited market makers\n\nSettlement dependence\n\nLiquidity often concentrates in a limited number of expiries and strikes.\n\nA distant contract may offer an attractive theoretical payoff but poor practical execution.\n\nThe spread should be considered part of the premium cost.\n\n### Model Risk\n\nOption pricing models use assumptions about:\n\nVolatility\n\nDistribution of returns\n\nInterest rates\n\nContinuous trading\n\nMarket liquidity\n\nReal cryptocurrency markets can experience:\n\nPrice jumps\n\nExchange outages\n\nStablecoin depegs\n\nLiquidation cascades\n\nFragmented liquidity\n\nExtreme skew\n\nThe model may provide useful estimates without capturing every real-world risk.\n\nThe Greeks and implied volatility should be treated as tools rather than objective truth.\n\n### Counterparty and Platform Risk\n\nAn option position depends on the platform’s ability to:\n\nHold collateral\n\nMatch trades\n\nCalculate margin\n\nProcess settlement\n\nHonour profits\n\nManage defaults\n\nCentralised platforms introduce custody and insolvency risk.\n\nDecentralised option protocols may introduce:\n\nSmart contract risk\n\nOracle risk\n\nLiquidity-pool risk\n\nGovernance risk\n\nBridge risk\n\nSettlement risk\n\nA defined payoff is meaningful only if the platform can honour it.\n\n### Decentralised Options\n\nDecentralised options may be created through smart contracts or tokenised option positions.\n\nPotential benefits include:\n\nOn-chain transparency\n\nSelf-custodial interaction\n\nProgrammable settlement\n\nComposability\n\nPotential risks include:\n\nSmart contract exploits\n\nWeak liquidity\n\nOracle manipulation\n\nExpensive network transactions\n\nComplex collateral mechanisms\n\nTokenised position risk\n\nThe absence of a conventional broker does not remove counterparty-like dependencies.\n\n### Option Vaults\n\nA DeFi vault may sell or buy options automatically on behalf of depositors.\n\nFor example, a vault may sell covered calls and distribute premium.\n\nThe strategy can appear passive.\n\nThe depositor is exposed to:\n\nVault contract risk\n\nStrategy design\n\nOption pricing\n\nCollateral management\n\nGovernance\n\nOpportunity cost\n\nUnderlying asset decline\n\nA high yield may reflect systematic sale of valuable upside or downside protection.\n\nThe source of return must be understood.\n\n### Yield From Option Selling\n\nOption premium can be presented as yield.\n\nFor example, a covered-call vault may earn regular premiums.\n\nThe return is not interest.\n\nIt is compensation for selling optionality.\n\nThe strategy may underperform badly when:\n\nThe underlying rallies beyond the strike\n\nVolatility rises\n\nLiquidity deteriorates\n\nThe underlying collapses\n\nA smooth sequence of small premium gains can conceal an unfavourable payoff during extreme markets.\n\n### Options and Portfolio Sizing\n\nThe maximum premium loss of a long option should still be limited to an appropriate percentage of capital.\n\nA defined loss does not justify risking the full portfolio.\n\nSuppose a trader repeatedly risks ten percent of capital on option premiums.\n\nFive unsuccessful trades can produce a severe drawdown.\n\nThe position should be sized according to:\n\nProbability of full premium loss\n\nExpected payoff\n\nStrategy frequency\n\nCorrelation\n\nPortfolio heat\n\nShort option positions require even more conservative sizing because losses can exceed the premium substantially.\n\n### Premium-at-Risk Model\n\nFor a standalone purchased option, the premium at risk is straightforward.\n\nSuppose:\n\nPortfolio: 100,000 units\n\nMaximum option risk: one percent\n\nRisk allowance: 1,000 units\n\nPremium per contract: 250 units\n\nMaximum contracts:\n\n1,000 ÷ 250 = 4 contracts\n\nThe entire premium should be treated as potentially lost.\n\nA stop on the option may reduce the realised loss, but option prices can move rapidly and spreads may widen.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,10,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-3-08-lesson-11','cognizen-crypto-mastery-foundations-production','Risk in Option Spreads and Taking Profit on Options','cmf-module-3-08','text','### Risk in Option Spreads\n\nFor a debit spread, the maximum loss is generally the net premium paid.\n\nFor a defined-risk credit spread, maximum loss is usually:\n\nDifference between strikes − Net premium received\n\nThe contract multiplier must then be applied.\n\nSuppose:\n\nStrike width: 20\n\nCredit received: 6\n\nMultiplier: 1\n\nMaximum loss:\n\n20 − 6 = 14 units\n\nThe position size should be based on that maximum loss rather than the premium income.\n\n### Portfolio Heat and Options\n\nSeveral long options can lose their premiums simultaneously if they depend on the same market movement.\n\nSeveral short-volatility positions can suffer at once during a market shock.\n\nPortfolio heat should group positions by:\n\nDirection\n\nVolatility exposure\n\nExpiry\n\nUnderlying asset\n\nExchange\n\nCollateral\n\nA portfolio may appear diversified by strategy name while remaining heavily short volatility across every position.\n\n### Scenario Analysis\n\nAn option should be evaluated across several possible outcomes.\n\nFor a long call, consider what happens if:\n\nThe underlying falls\n\nIt remains unchanged\n\nIt rises slowly\n\nIt rises rapidly\n\nImplied volatility falls\n\nImplied volatility rises\n\nThe movement occurs immediately\n\nThe movement occurs near expiry\n\nA payoff diagram at expiry captures only one part of the position.\n\nOptions are path dependent in practical trading because the timing and volatility of the movement affect market value before expiry.\n\n### Stress Testing Short Options\n\nA short option strategy should be tested against movements much larger than recent history.\n\nConsider:\n\nUnderlying falls fifty percent\n\nUnderlying doubles\n\nImplied volatility triples\n\nMarket liquidity disappears\n\nMargin requirements rise\n\nHedge orders fail\n\nExchange becomes unavailable\n\nA short option strategy that survives only ordinary conditions is not robust.\n\nTail risk should be treated as a central feature, not an unlikely exception.\n\n### Choosing Between Options and Futures\n\nA trader expecting a directional movement may choose between options and futures.\n\nA future provides relatively direct price exposure and may be cheaper when the movement occurs as expected.\n\nIt also creates liquidation and potentially larger loss risk.\n\nAn option limits the buyer’s maximum loss to the premium but requires sufficient movement before time and volatility costs overwhelm the position.\n\nThe choice depends on:\n\nExpected direction\n\nExpected size of movement\n\nTiming\n\nVolatility pricing\n\nDesired maximum loss\n\nLiquidity\n\nFunding\n\nHolding period\n\nOptions are not automatically safer or more profitable.\n\nThey create a different payoff structure.\n\n### Choosing Between Options and Spot\n\nSpot ownership has no expiry and does not suffer option time decay.\n\nIt requires more capital and carries the full downside risk of the asset.\n\nA call option uses less initial capital and limits loss to the premium.\n\nIt may expire worthless even when the long-term investment thesis remains correct but takes too long to unfold.\n\nA long-term investor should not use a short-dated call to express a multi-year view without recognising the timing mismatch.\n\n### Options Trade Plan\n\nAn options trade plan should identify the exact underlying, strike, expiry, contract multiplier and settlement method.\n\nIt should explain whether the position is directional, volatility based, protective or income seeking.\n\nThe plan should state the maximum loss, expected break-even, target and conditions for early exit.\n\nIt should also define the assumptions regarding:\n\nUnderlying movement\n\nTiming\n\nImplied volatility\n\nLiquidity\n\nEvent risk\n\nA statement such as “I expect the asset to rise” is not enough.\n\nThe option buyer must expect it to rise sufficiently, soon enough and relative to the premium paid.\n\n### Managing a Long Option\n\nA long option can be managed by:\n\nHolding to expiry\n\nSelling after a favourable underlying move\n\nSelling after implied volatility rises\n\nExiting when the thesis fails\n\nRolling to another strike or expiry\n\nConverting into a spread\n\nHolding to expiry is not always optimal.\n\nAn option may contain substantial remaining time value that can be realised through sale.\n\nExercising can forfeit extrinsic value, depending on the contract and circumstances.\n\n### Rolling an Option\n\nRolling generally means closing one option and opening another.\n\nThe trader may roll:\n\nTo a later expiry\n\nTo a different strike\n\nBoth strike and expiry\n\nRolling does not erase a loss.\n\nIt closes one position and creates a new one.\n\nThe new trade should be evaluated independently.\n\nRepeated rolling can turn one defined premium loss into a much larger cumulative loss.\n\n### Taking Profit on Options\n\nAn option can appreciate rapidly because of directional movement and volatility expansion.\n\nA trader may take profit before expiry rather than waiting for the maximum theoretical payoff.\n\nThe plan may use:\n\nPercentage gain\n\nUnderlying price target\n\nImplied-volatility target\n\nTime remaining\n\nPartial exits\n\nOptions can lose value quickly after a favourable event if implied volatility collapses.\n\nUnrealised option profit should not be assumed to remain stable.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,11,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-3-08-lesson-12','cognizen-crypto-mastery-foundations-production','Stop-Losses on Options and Common Misunderstandings','cmf-module-3-08','text','### Stop-Losses on Options\n\nOption stop orders can be difficult because option prices may have:\n\nWide spreads\n\nLow volume\n\nRapid volatility changes\n\nTemporary quote gaps\n\nA stop based only on the option premium can be triggered even when the underlying thesis remains intact.\n\nSome traders use the underlying asset’s invalidation level rather than the option’s price.\n\nThe correct method depends on liquidity and strategy.\n\nThe maximum premium loss should always remain acceptable even if the stop fails.\n\n### Options Checklist\n\nBefore entering an option position, confirm the following:\n\nWhat is the underlying asset?\n\nIs the contract a call or put?\n\nAm I buying or selling the option?\n\nWhat is the strike price?\n\nWhat is the expiry date and exact expiry time?\n\nIs the option European, American or another exercise style?\n\nHow is it settled?\n\nWhat does one contract represent?\n\nIn which asset is premium and settlement denominated?\n\nWhat is the bid-ask spread?\n\nWhat are current volume and open interest?\n\nIs the option in, at or out of the money?\n\nHow much intrinsic and extrinsic value does it contain?\n\nWhat is the implied volatility?\n\nIs IV high or low relative to its own history?\n\nWhat movement is already priced into the premium?\n\nWhat are the option’s delta, gamma, theta and vega?\n\nIs the position long or short volatility?\n\nWhat is the maximum possible loss?\n\nWhat is the maximum potential profit?\n\nWhat is the break-even price at expiry?\n\nDoes the thesis require a specific direction, size and timing?\n\nWhat happens if implied volatility falls?\n\nIs a major event approaching?\n\nIs the strategy speculative, protective or income producing?\n\nIs the option covered, cash secured, defined risk or naked?\n\nWhat margin could be required?\n\nWhat platform, oracle or settlement risks exist?\n\nHow will the position be exited or rolled?\n\nCan the portfolio tolerate the full planned loss?\n\n### Common Options Mistakes\n\nA common error is buying an option because its premium appears cheap. A low-priced option may be cheap because the probability of a valuable payoff is extremely low.\n\nAnother mistake is focusing only on direction. The trader may correctly predict a rise but underestimate time decay or volatility crush.\n\nParticipants may also compare options using premium alone while ignoring contract multipliers, strikes and expiry dates.\n\nOption sellers often treat premium as immediate income without recognising the obligation and tail risk being accepted.\n\nA further error is choosing expiry according to price rather than allowing enough time for the thesis to develop.\n\nFinally, some traders roll losing positions repeatedly and describe the action as avoiding a loss. Each roll realises the old result and opens a new risk.\n\n### Common Misunderstandings\n\n#### “Buying an Option Is Safer Because the Loss Is Limited”\n\nThe maximum loss is defined, but the probability of losing the entire premium can be high.\n\n#### “A Call Profits Whenever the Underlying Rises”\n\nThe rise must be sufficient relative to premium, time decay and volatility changes.\n\n#### “An Option Must Reach Break-Even Before It Can Be Sold Profitably”\n\nThe expiry break-even does not determine every pre-expiry market value.\n\n#### “Out-of-the-Money Options Offer the Best Leverage”\n\nThey offer inexpensive exposure but may have a very low probability of producing value.\n\n#### “Selling Options Produces Passive Income”\n\nIt earns premium in exchange for accepting potentially severe obligations.\n\n#### “A Covered Call Protects the Portfolio From a Crash”\n\nThe premium provides only limited protection against a large underlying decline.\n\n#### “A Cash-Secured Put Guarantees a Good Entry Price”\n\nThe asset can fall far below the effective purchase price because of genuine deterioration.\n\n#### “High Implied Volatility Means Price Will Fall”\n\nImplied volatility reflects expected movement size, not direction.\n\n#### “A Volatility Crush Happens Only When Price Does Not Move”\n\nIt can occur after a major event even when the underlying moves substantially.\n\n#### “Delta Is the Exact Probability of Profit”\n\nDelta is a model-based sensitivity measure and only a rough probability proxy under certain assumptions.\n\n#### “Theta Income Is Free”\n\nOption sellers earn theta while accepting negative gamma and tail risk.\n\n#### “Market-Neutral Option Strategies Are Risk-Free”\n\nThey remain exposed to volatility, liquidity, model, margin and platform risks.\n\n#### “Holding to Expiry Is Always the Best Way to Realise Option Value”\n\nSelling earlier may preserve remaining extrinsic value and reduce event risk.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,12,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-3-08-lesson-13','cognizen-crypto-mastery-foundations-production','Module Summary and Key Takeaway','cmf-module-3-08','text','### Module Summary\n\nAn option gives its buyer a contractual right relating to an underlying asset.\n\nA call provides the right associated with buying at the strike price.\n\nA put provides the right associated with selling at the strike price.\n\nThe buyer pays premium and generally has a defined maximum loss.\n\nThe seller receives premium and accepts an obligation that can create much larger losses.\n\nEvery option is defined by its underlying asset, strike, expiry, multiplier, settlement method and exercise style.\n\nAn option’s premium consists of intrinsic and extrinsic value.\n\nIntrinsic value reflects immediate exercise value.\n\nExtrinsic value reflects remaining time, expected volatility and market demand.\n\nOptions may be in, at or out of the money.\n\nThe buyer’s expiry break-even includes the premium paid, but an option can be traded profitably or unprofitably before that price is reached.\n\nImplied volatility reflects the market’s pricing of future uncertainty.\n\nRealised volatility measures how much the asset actually moved.\n\nOption buyers generally benefit from greater-than-expected movement and rising implied volatility.\n\nOption sellers generally benefit from time decay and lower-than-expected movement, while carrying potentially severe tail risk.\n\nThe main Greeks describe different dimensions of option exposure.\n\nDelta measures directional sensitivity.\n\nGamma measures the rate at which delta changes.\n\nTheta measures time decay.\n\nVega measures sensitivity to implied volatility.\n\nRho measures interest-rate sensitivity.\n\nBasic strategies include long calls, long puts, protective puts, covered calls, cash-secured puts, collars and vertical spreads.\n\nStraddles and strangles create exposure to movement in either direction but require the movement to exceed the combined premiums.\n\nOptions can support speculation, hedging, portfolio protection and income strategies.\n\nTheir flexibility does not remove risk.\n\nA trader must be correct not only about direction, but often about magnitude, timing and volatility.\n\nThe most important question is not whether an option position has a limited premium or an attractive maximum payoff.\n\nIt is whether the complete payoff structure matches the market thesis and whether the portfolio can tolerate the position’s realistic loss.\n\n### Key Takeaway\n\nOptions allow you to shape risk rather than merely increase or decrease market exposure.\n\nA call, put or spread can define maximum loss, protect a portfolio, limit upside or create exposure to volatility itself.\n\nThat flexibility has a price.\n\nOption value depends on direction, movement size, timing, volatility and liquidity.\n\nBefore entering, understand exactly what must happen, how soon it must happen and what the market has already priced into the premium.\n\nThe next module is 3.9: Options Greeks, Volatility and Advanced Strategies.','markdown',NULL,NULL,NULL,4,0,0,0,'',NULL,13,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-3-08-lesson-14','cognizen-crypto-mastery-foundations-production','Check your understanding','cmf-module-3-08','text','### Check your understanding\n\nAnswer these questions to self-assess your understanding before moving on.\n\n1. What is an option?\n\n2. How does a call differ from a put?\n\n3. What right does a call buyer receive?\n\n4. What right does a put buyer receive?\n\n5. How does an option buyer differ from an option seller?\n\n6. What is the strike price?\n\n7. What is the expiry date?\n\n8. How do European- and American-style options differ?\n\n9. What is cash settlement?\n\n10. Why is the contract multiplier important?\n\n11. How is total option premium calculated?\n\n12. What does moneyness describe?\n\n13. When is a call in the money?\n\n14. When is a put in the money?\n\n15. What is intrinsic value?\n\n16. What is extrinsic value?\n\n17. Why does extrinsic value approach zero at expiry?\n\n18. How is the expiry break-even for a long call calculated?\n\n19. How is the expiry break-even for a long put calculated?\n\n20. What is the maximum loss on a standalone long option?\n\n21. Why can an uncovered short call produce theoretically unlimited loss?\n\n22. What information appears in an options chain?\n\n23. Why are bid-ask spreads important in option markets?\n\n24. How does option volume differ from open interest?\n\n25. What is implied volatility?\n\n26. How does implied volatility differ from realised volatility?\n\n27. What is a volatility crush?\n\n28. What is volatility skew?\n\n29. What does put skew indicate about option pricing?\n\n30. What is volatility term structure?\n\n31. What does delta measure?\n\n32. What does gamma measure?\n\n33. What does theta measure?\n\n34. What does vega measure?\n\n35. Why are the Greeks estimates rather than guarantees?\n\n36. What are the main risks of a long call?\n\n37. How can a protective put reduce portfolio downside?\n\n38. Why does a covered call limit upside?\n\n39. What is a cash-secured put?\n\n40. How does a collar work?\n\n41. What is a bull call spread?\n\n42. What is a bear put spread?\n\n43. How does a long straddle express a volatility view?\n\n44. How does a strangle differ from a straddle?\n\n45. Why are short straddles and strangles dangerous?\n\n46. What does long volatility mean?\n\n47. Why may an option buyer lose after correctly predicting direction?\n\n48. What is an expected move?\n\n49. What is tail-risk hedging?\n\n50. What is delta hedging?\n\n51. How does positive gamma benefit an option buyer?\n\n52. What trade-off exists between gamma and theta?\n\n53. What is a naked option?\n\n54. How does a defined-risk spread limit loss?\n\n55. What is assignment?\n\n56. What is pin risk?\n\n57. Why can expiry-day option sensitivity change rapidly?\n\n58. What is model risk?\n\n59. How can a DeFi option vault generate yield?\n\n60. Why should option-selling yield not be treated as interest?\n\n61. How should a long option position be sized?\n\n62. What is premium-at-risk?\n\n63. How is maximum loss calculated for a debit spread?\n\n64. Why must several option positions be assessed at portfolio level?\n\n65. What factors should an options trade plan include?','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,14,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `course_sections` (`id`,`course_id`,`title`,`position`,`created_at`) SELECT 'cmf-module-3-09','cognizen-crypto-mastery-foundations-production','Module 3.9: Options Greeks and Advanced Strategies',10,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
