INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-3-13-lesson-01','cognizen-crypto-mastery-foundations-production','What Is a Holder Cohort? and Holding Period','cmf-module-3-13','text','### Learning Objectives\n\nBy the end of this module, you should understand how analysts use wallet activity to study the behaviour of different groups of digital asset holders.\n\nYou should be able to explain how holders may be classified according to wallet balance, holding period, cost basis, spending behaviour and activity level. You should also understand the difference between an address, a wallet and an economic entity, and why large-address data can be misleading when exchanges, custodians, bridges and smart contracts are not identified correctly.\n\nThe module will show how holder cohorts can contribute to market-cycle analysis, supply assessment and risk management without implying that blockchain records reveal the exact identity or intention of every participant.\n\n### Introduction\n\nEvery blockchain transaction changes part of the network’s ownership record.\n\nAssets move from one address to another. Previously inactive coins become active. New addresses receive tokens, while older wallets reduce or increase their balances.\n\nThese movements create a detailed history of asset behaviour.\n\nBy organising wallets and assets into groups, analysts can explore questions such as:\n\nAre long-term holders continuing to accumulate?\n\nAre recent buyers selling at a loss?\n\nAre large holders moving assets toward exchanges?\n\nIs supply becoming more concentrated?\n\nWhich holders are most vulnerable to a market decline?\n\nAre older coins returning to circulation?\n\nThese questions can reveal information that an ordinary price chart cannot show.\n\nHowever, blockchain records do not provide a complete investor registry.\n\nOne person can control many addresses. One exchange address can represent assets belonging to millions of customers. A decentralised finance contract may hold tokens for thousands of depositors.\n\nThe movement of an asset also does not reveal its purpose automatically.\n\nA transfer may represent a sale, purchase, collateral deposit, custody migration, internal reorganisation, bridge transaction or smart contract interaction.\n\nHolder analysis is therefore a process of classification and inference.\n\nThe data may be precise, while the economic interpretation remains uncertain.\n\n### What Is a Holder Cohort?\n\nA holder cohort is a group of assets, addresses or entities sharing a defined characteristic.\n\nThe characteristic may be based on holding period, balance size, estimated cost basis, activity level or realised profit and loss.\n\nFor example, analysts may separate supply into assets that have not moved for more than one year and assets acquired during the past month.\n\nThey may also compare addresses holding small balances with entities controlling very large positions.\n\nCohorts help simplify a complex market.\n\nInstead of examining millions of individual transactions, the analyst studies how groups behave over time.\n\nThe usefulness of the analysis depends on whether the grouping reflects a meaningful economic distinction.\n\nAn arbitrary classification can create attractive charts without improving understanding.\n\n### Address, Wallet and Entity\n\nAn address is a location on a blockchain associated with cryptographic control.\n\nA wallet is the software or hardware used to manage one or more addresses.\n\nAn entity is the person, institution, exchange, protocol or organisation believed to control the addresses.\n\nThese distinctions are essential.\n\nSuppose one exchange controls ten thousand addresses.\n\nCounting each address as an independent investor would create a false impression of ownership distribution.\n\nConversely, one investor may hold assets through several self-custody wallets, centralised exchanges and decentralised protocols.\n\nNo single address would show the complete exposure.\n\nHolder analysis becomes more meaningful when addresses can be grouped into probable entities.\n\nThat process is never perfect.\n\n### Entity Adjustment\n\nEntity-adjusted metrics attempt to remove movements occurring between addresses controlled by the same organisation.\n\nSuppose an exchange moves assets from an old cold wallet into a new wallet.\n\nThe blockchain records a large transfer.\n\nWithout entity adjustment, the movement may appear to be a major whale transaction or exchange outflow.\n\nIf both addresses belong to the same exchange, no beneficial ownership may have changed.\n\nEntity adjustment reduces this type of noise.\n\nIt relies on address labels and clustering methods that can be incomplete or incorrect.\n\nThe adjusted metric may be more economically useful, but it is also further removed from the raw blockchain record.\n\n### Holding Period\n\nOne of the most common ways to classify holders is according to how long their assets have remained unmoved.\n\nAssets that have not moved for a long period may be associated with patient investors, dormant holdings, institutional storage or lost keys.\n\nRecently moved assets may be associated with active traders, new investors or operational transactions.\n\nHolding period is easier to estimate on UTXO-based networks, where individual outputs have identifiable ages.\n\nOn account-based networks, assets can be transferred, pooled and reused in ways that make age analysis more complicated.\n\nThe time since an asset last moved should not be confused with the time since the current owner originally purchased it.\n\nA custody transfer can reset the apparent age without changing the economic owner.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,1,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-3-13-lesson-02','cognizen-crypto-mastery-foundations-production','Long-Term Holders and HODL Waves','cmf-module-3-13','text','### Long-Term Holders\n\nLong-term holders are generally defined as entities or coin units that have remained inactive beyond a selected threshold.\n\nThe threshold is determined by the analytics methodology.\n\nLong-term holders are often assumed to have stronger conviction and lower sensitivity to ordinary price volatility.\n\nDuring market expansions, they may gradually distribute assets to newer buyers.\n\nDuring declines, they may continue holding or accumulate additional supply.\n\nThis behaviour is not universal.\n\nA long-held asset can be sold suddenly because the owner’s circumstances, expectations or access have changed.\n\nThe cohort describes historical behaviour, not a contractual commitment to continue holding.\n\n### Short-Term Holders\n\nShort-term holders generally control assets acquired or moved more recently.\n\nThey may include new investors, active traders, market makers and participants responding to current narratives.\n\nTheir estimated cost basis is often closer to the current market price.\n\nThis can make the cohort more sensitive to short-term movement.\n\nWhen price falls below the average short-term holder cost basis, recent buyers may experience unrealised losses.\n\nSome may sell to limit further loss, increasing market pressure.\n\nOthers may hold or purchase more.\n\nThe cohort provides information about potential sensitivity, not predetermined behaviour.\n\n### Holder Thresholds\n\nThere is no natural line separating a long-term holder from a short-term holder.\n\nAnalytics platforms may define cohorts using a specific number of days or a statistical model based on spending probability.\n\nDifferent thresholds produce different results.\n\nThe analyst should understand how the category was created before comparing data from different providers.\n\nA holder classified as long term by one model may remain short term under another.\n\nConsistency is more important than treating one threshold as universally correct.\n\n### Dormant Supply\n\nDormant supply refers to assets that have not moved for a substantial period.\n\nGrowing dormant supply may suggest that more holders are keeping assets inactive.\n\nThis can reduce the quantity immediately circulating in markets.\n\nDormancy may also include permanently lost assets.\n\nIf private keys have been destroyed or forgotten, the tokens remain visible but cannot return to circulation.\n\nAnalysts rarely know with certainty which dormant assets are intentionally held and which are inaccessible.\n\nDormant supply should therefore be interpreted as inactive rather than automatically available long-term investment supply.\n\n### Reactivated Supply\n\nReactivated supply consists of older assets that begin moving again.\n\nA rise in reactivated supply can indicate that long-term holders are becoming more active.\n\nThis may occur during a strong rally when older investors decide to realise profits.\n\nIt can also occur during a market crisis, custody migration or institutional restructuring.\n\nThe destination helps provide context.\n\nOld coins moving toward a recognised exchange create a different risk interpretation from coins moving into another long-term custody address.\n\nEven then, the intended action is uncertain.\n\n### Coin Age\n\nCoin age combines the quantity of an asset with the time it has remained unspent or unmoved.\n\nOne coin held for one hundred days carries one hundred coin days.\n\nTen coins held for the same period carry one thousand coin days.\n\nWhen old supply moves, a large amount of coin age is destroyed.\n\nThis can draw attention to transactions involving historically inactive assets.\n\nCoin age is especially useful for studying whether market activity is dominated by recently circulating supply or older holdings.\n\n### Coin Days Destroyed\n\nCoin Days Destroyed measures the coin age consumed when assets move.\n\nA large reading may occur when a substantial quantity of old supply becomes active.\n\nSuppose one hundred coins remain inactive for one thousand days.\n\nWhen they move, they destroy:\n\n100 × 1,000 = 100,000 coin days\n\nThe movement may indicate long-term holder distribution.\n\nIt may also be an internal transfer.\n\nCoin Days Destroyed should be examined alongside destination, realised value and broader market conditions.\n\n### Dormancy\n\nDormancy commonly relates coin age destroyed to transaction volume.\n\nIt attempts to estimate the average age of coins being spent.\n\nHigher dormancy suggests that older supply is becoming more active.\n\nLower dormancy suggests that current activity is dominated by recently moved assets.\n\nA sudden dormancy spike may attract attention during a market rally.\n\nA sustained increase across several periods is generally more informative than one isolated transfer.\n\n### HODL Waves\n\nHODL waves divide supply into bands according to the time since it last moved.\n\nThe chart may show how much supply has remained inactive for periods such as less than one month, several months, one year or multiple years.\n\nAs time passes without movement, supply migrates into older bands.\n\nWhen old assets move, they return to younger age bands.\n\nHODL waves can help identify accumulation, maturation and distribution.\n\nThey should not be interpreted as a direct count of committed investors.\n\nThe bands reflect coin age rather than verified investor intent.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,2,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-3-13-lesson-03','cognizen-crypto-mastery-foundations-production','Realised Cap HODL Waves and Realised Profit','cmf-module-3-13','text','### Realised Cap HODL Waves\n\nOrdinary HODL waves weight each age band by the amount of supply.\n\nRealised cap HODL waves may weight the bands according to the value at which assets last moved.\n\nThis gives greater economic significance to coins transferred at higher prices.\n\nThe metric can help show which holding periods account for a larger share of the network’s estimated cost basis.\n\nIt remains dependent on the assumptions behind realised capitalisation.\n\n### Cost Basis\n\nA holder’s cost basis is the effective price at which the asset was acquired.\n\nOn-chain data does not always reveal the true purchase price.\n\nAn asset may have been purchased on an exchange and withdrawn later. The withdrawal transaction records the market price at the time of transfer, not necessarily the price originally paid.\n\nOn-chain models often use the price when the asset last moved as a proxy.\n\nThis can produce an estimated aggregate cost basis.\n\nIt is useful for cohort analysis but should not be mistaken for verified accounting records.\n\n### Realised Price by Cohort\n\nA realised price can be calculated for different holder groups.\n\nExamples include the estimated cost basis of long-term holders, short-term holders or holders active during a specific period.\n\nSuppose the short-term holder realised price is 50,000 units.\n\nWhen market price remains above this level, recent participants are collectively estimated to be in profit.\n\nWhen price falls below it, recent participants are estimated to be holding unrealised losses.\n\nThe level may act as a behavioural reference.\n\nIt is not a guaranteed support or resistance price.\n\n### Short-Term Holder Cost Basis\n\nThe short-term holder cost basis is often closely watched because recent buyers may be more price sensitive.\n\nDuring a strong bull regime, price may repeatedly recover near this level as buyers defend positions or new demand enters.\n\nDuring a bear regime, the same level may act as resistance because recent holders use recoveries to exit near break-even.\n\nThe interpretation depends on market structure.\n\nA cost-basis line should not be traded without confirmation from price, volume and liquidity.\n\n### Long-Term Holder Cost Basis\n\nThe estimated cost basis of long-term holders is usually lower and changes more slowly.\n\nPrice falling below it may indicate severe market stress because even historically patient holders are collectively under pressure.\n\nSuch conditions have sometimes occurred during major market downturns.\n\nHistorical rarity does not guarantee immediate reversal.\n\nA market can remain below aggregate cost basis while fundamental, regulatory or liquidity problems continue.\n\n### Unrealised Profit and Loss\n\nUnrealised profit exists when the current market price exceeds an asset’s estimated cost basis.\n\nUnrealised loss exists when the price is lower.\n\nCohort-level unrealised profit and loss can help identify psychological pressure.\n\nA market in which most recent buyers hold substantial profits may support optimism and further risk-taking.\n\nIt may also create a large pool of potential sellers.\n\nA market in which most holders are in loss may produce capitulation.\n\nIt can also remain depressed because buyers are unwilling to return.\n\n### Net Unrealised Profit and Loss\n\nNet Unrealised Profit and Loss, or NUPL, compares estimated unrealised profit with unrealised loss across the network.\n\nA positive value suggests that aggregate unrealised profit is greater.\n\nA negative value suggests aggregate unrealised loss.\n\nAnalysts sometimes divide NUPL into broad sentiment zones associated with optimism, belief, fear or capitulation.\n\nThese labels are descriptive.\n\nThey should not create the impression that every holder shares one emotional state.\n\nThe metric estimates economic conditions, not actual investor psychology.\n\n### Relative Unrealised Profit\n\nRelative unrealised profit estimates the market’s aggregate unrealised gains relative to market value.\n\nHigh readings may occur during strong bull markets.\n\nThey can indicate that a large share of holders has substantial paper profit.\n\nThis may support continued confidence while also increasing the incentive to take profit.\n\nThe metric can remain elevated for extended periods.\n\nIt should not be used to short a market merely because holders are profitable.\n\n### Relative Unrealised Loss\n\nRelative unrealised loss estimates aggregate paper losses relative to market value.\n\nHigh readings can indicate broad financial stress.\n\nThey may occur during capitulation or prolonged bear markets.\n\nThe metric becomes more useful when combined with realised losses and evidence that selling is beginning to exhaust.\n\nLarge unrealised losses alone do not mean that holders have finished selling.\n\n### Realised Profit\n\nRealised profit is estimated when assets move at a higher market price than the price at which they last moved.\n\nA rise in realised profit may indicate that holders are taking gains.\n\nProfit realisation is normal during a healthy bull market.\n\nThe important question is whether new demand can absorb the distributed supply.\n\nIf price continues rising despite substantial realised profit, the market may have strong demand.\n\nIf price stalls or falls while realised profit expands, distribution may be overcoming demand.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,3,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-3-13-lesson-04','cognizen-crypto-mastery-foundations-production','Realised Loss and Mega-Whales and Concentration','cmf-module-3-13','text','### Realised Loss\n\nRealised loss is estimated when assets move below their previous last-moved price.\n\nA rise in realised loss may indicate capitulation, forced selling or tax-related activity.\n\nLarge realised losses often occur during severe declines.\n\nThey can help reveal when holders are abandoning positions.\n\nA loss event does not identify the market bottom.\n\nContinued deterioration can produce repeated waves of realised loss.\n\n### Net Realised Profit and Loss\n\nNet realised profit and loss compares profit-taking with loss realisation.\n\nPositive readings suggest more profit is being realised than loss.\n\nNegative readings suggest loss-taking dominates.\n\nThe metric can help characterise market phases.\n\nA mature bull market may show sustained profit realisation.\n\nA severe bear market may show repeated negative readings.\n\nTransition periods may occur when realised losses diminish and profit-taking gradually returns.\n\n### Spent Output Profit Ratio\n\nThe Spent Output Profit Ratio, or SOPR, compares the market value of assets when spent with their value when previously moved.\n\nA value above one suggests that spent assets moved at an aggregate profit.\n\nA value below one suggests aggregate loss.\n\nA value near one suggests movement close to estimated break-even.\n\nDuring bullish regimes, SOPR may fall toward one and recover as holders resist selling at a loss.\n\nDuring bearish regimes, it may rise toward one and fail as holders use break-even opportunities to exit.\n\nThis is a behavioural interpretation rather than a guaranteed market rule.\n\n### Adjusted SOPR\n\nAdjusted SOPR may exclude very young outputs or certain transactions that create noise.\n\nThe objective is to focus on economically meaningful spending.\n\nDifferent providers may use different adjustment rules.\n\nThe adjusted metric should not be compared directly with an unadjusted version without understanding the methodological difference.\n\n### Long-Term Holder SOPR\n\nLong-Term Holder SOPR isolates estimated profit and loss realised by older supply.\n\nLarge positive readings may indicate that long-term holders are distributing after substantial appreciation.\n\nReadings below one may show that older holders are selling at a loss, which can indicate severe stress.\n\nThe metric should be interpreted alongside the amount of supply moving.\n\nA high ratio on very small volume may be less important than moderate profit realisation involving significant supply.\n\n### Short-Term Holder SOPR\n\nShort-Term Holder SOPR focuses on recently active supply.\n\nIt can help assess whether newer participants are selling at gains or losses.\n\nFrequent movement around one may reflect a contested cost-basis area.\n\nDuring a strong trend, recent buyers may consistently realise profits.\n\nDuring weakness, repeated loss realisation can indicate that new demand is being discouraged.\n\n### Holder Balance Cohorts\n\nWallets or entities may also be classified according to balance size.\n\nInformal labels often include:\n\nShrimp for very small holders\n\nFish or dolphins for medium-sized holders\n\nWhales for very large holders\n\nThe exact boundaries vary and are not standardised.\n\nBalance cohorts can show whether supply is moving toward larger or smaller holders.\n\nThe analysis should be entity adjusted where possible.\n\nOtherwise, exchanges and smart contracts can dominate the largest categories.\n\n### Small-Holder Accumulation\n\nAn increase in supply held by small addresses may indicate broader retail participation.\n\nIt may also result from one organisation distributing assets across many addresses.\n\nSmall-holder accumulation can be constructive when it accompanies genuine user growth and improving ownership distribution.\n\nIt may be a late-cycle warning when large holders are selling to enthusiastic new entrants at rapidly increasing prices.\n\nThe direction of transfer between cohorts matters.\n\n### Large-Holder Accumulation\n\nLarge entities increasing their balances may indicate institutional or high-net-worth accumulation.\n\nThe interpretation depends on whether the addresses belong to independent investors, exchanges, funds, protocols or custodians.\n\nA custodian receiving assets for many clients may appear to be one accumulating whale.\n\nLarge-holder accumulation is more meaningful when labels and transaction context support the conclusion.\n\n### Whale Distribution\n\nWhale distribution occurs when large holders reduce their asset balances.\n\nThis can add meaningful market supply.\n\nWhales may distribute gradually through exchanges, over-the-counter trades, decentralised liquidity or transfers to smaller addresses.\n\nA falling large-address balance does not always represent selling.\n\nAn entity may restructure custody or divide assets among several wallets.\n\nEntity-level analysis is necessary.\n\n### Mega-Whales and Concentration\n\nVery large holders can create systemic risk when they control enough supply to affect price, governance or liquidity.\n\nThe risk depends on:\n\nPercentage of circulating supply\n\nMarket depth\n\nToken unlock rules\n\nRelationship to the project\n\nCustody structure\n\nHistorical selling behaviour\n\nA founder wallet controlling twenty percent of a thinly traded token presents a different risk from an exchange custody wallet holding the same percentage for customers.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,4,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-3-13-lesson-05','cognizen-crypto-mastery-foundations-production','Exchange Wallets as Holder Cohorts and Illiquid Supply','cmf-module-3-13','text','### Exchange Wallets as Holder Cohorts\n\nExchange wallets often appear among the largest addresses.\n\nTheir balances belong partly or entirely to customers.\n\nTreating them as one holder overstates concentration and creates false whale signals.\n\nExchange balance changes can still be economically important because they affect readily tradable supply.\n\nThe correct classification is usually exchange reserves rather than individual ownership.\n\n### Custodian Wallets\n\nInstitutional custodians may hold assets for funds, companies and private clients.\n\nOne custodian address can represent many beneficial owners with different intentions.\n\nMovement into custody may indicate long-term storage, regulatory compliance or product creation.\n\nMovement out may represent redemption, transfer or sale.\n\nThe wallet label provides context but not complete intent.\n\n### Protocol and Smart Contract Wallets\n\nSmart contracts may hold substantial token balances.\n\nExamples include staking contracts, bridges, lending protocols, vesting contracts and liquidity pools.\n\nThese balances are controlled according to code and governance rules rather than by an ordinary individual wallet.\n\nIncluding them in whale analysis can create severe distortion.\n\nThe analyst should separate:\n\nUser-controlled balances\n\nExchange reserves\n\nProtocol-controlled assets\n\nLocked or vesting supply\n\nBurn addresses\n\n### Burn Addresses\n\nBurn addresses contain assets considered inaccessible or permanently removed from circulation.\n\nThey may appear as enormous holders.\n\nIncluding them in ownership-concentration analysis is misleading because the assets cannot ordinarily be sold or used for governance.\n\nBurned supply should be identified separately.\n\nThe method of burning should also be verified.\n\nA project-controlled wallet described informally as a burn wallet may not be cryptographically inaccessible.\n\n### Vesting and Locked Wallets\n\nTokens held in vesting contracts may not be immediately transferable.\n\nThey still represent future potential supply.\n\nCohort analysis should distinguish between circulating balances and locked allocations.\n\nAs unlock dates approach, assets may move from vesting contracts to team, investor or treasury wallets.\n\nThe transfer itself may be expected under the token schedule.\n\nWhether the recipients sell is a separate question.\n\n### Accumulation\n\nAccumulation describes a period during which holders increase exposure, often without immediately selling.\n\nOn-chain evidence may include rising balances among selected cohorts, declining exchange supply and increasing dormant supply.\n\nAccumulation is not always visible through one metric.\n\nFor every buyer, there is a seller.\n\nThe useful question is which group is gaining ownership and which group is distributing.\n\nA transfer from short-term speculative holders to financially stronger long-term holders may improve supply stability.\n\nThis remains an interpretation based on cohort behaviour.\n\n### Distribution\n\nDistribution describes supply moving from existing holders to new buyers.\n\nDuring a rising market, long-term holders may gradually realise profits while new demand absorbs the supply.\n\nDistribution does not automatically mean a market top.\n\nHealthy markets require some turnover and liquidity.\n\nThe risk increases when distribution accelerates while price momentum and new demand weaken.\n\nOn-chain distribution evidence becomes more significant when combined with failed price breakouts, declining breadth or weakening spot demand.\n\n### Reaccumulation\n\nReaccumulation may occur during a pause within a broader upward trend.\n\nPrice consolidates while strong holders continue accumulating supply from participants taking profit.\n\nThe market later resumes rising if demand remains sufficient.\n\nIt is difficult to distinguish reaccumulation from distribution before the range resolves.\n\nHolder data may provide clues, but price acceptance outside the range remains important confirmation.\n\n### Redistribution\n\nRedistribution occurs when supply changes hands during a pause in a broader declining trend and the market later continues downward.\n\nNew buyers may interpret lower prices as attractive while existing holders reduce exposure.\n\nAs with reaccumulation, the classification becomes clearer only after price leaves the range.\n\nOn-chain analysis can improve the probability assessment but cannot remove this uncertainty.\n\n### Holder Conviction\n\nConviction is often inferred from how long assets remain inactive and how holders respond to volatility.\n\nA cohort that continues holding through large price changes may appear more committed.\n\nThe term should be used cautiously.\n\nInactivity may also result from forgotten keys, tax restrictions, legal lock-ups, institutional mandates or operational delays.\n\nOn-chain data shows non-movement.\n\nThe reason for that non-movement remains uncertain.\n\n### Illiquid Supply\n\nIlliquid supply refers to assets held by entities with a history of receiving more than they spend.\n\nThese holders are considered less likely to sell immediately.\n\nLiquid supply is held by entities with more active spending behaviour.\n\nHighly liquid supply is associated with frequent movement or trading.\n\nA rising illiquid supply estimate may suggest that more assets are moving into stronger holding patterns.\n\nThe classification depends on historical behaviour and may change when an entity suddenly becomes active.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,5,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-3-13-lesson-06','cognizen-crypto-mastery-foundations-production','Liquid Supply and UTXO Realised Price Distribution','cmf-module-3-13','text','### Liquid Supply\n\nLiquid supply can move more readily into markets.\n\nIt may be held by exchanges, traders, market makers or active investors.\n\nA high amount of liquid supply can support healthy trading depth.\n\nIt can also increase potential selling pressure.\n\nLiquidity is not inherently bearish.\n\nMarkets require available supply to function.\n\nThe concern arises when liquid supply expands rapidly while demand weakens.\n\n### Supply Shock\n\nA supply-shock thesis argues that available market supply is declining while demand remains stable or increases.\n\nEvidence may include falling exchange balances, rising illiquid supply and long-term holder accumulation.\n\nThis can support price appreciation.\n\nThe conclusion depends on whether the measures identify genuine economic ownership.\n\nIt must also consider new issuance, token unlocks, derivatives exposure and off-chain custodial supply.\n\nA declining exchange balance does not mean that no assets are available for sale.\n\n### Lost Coins\n\nLost coins remain visible on-chain but may no longer be economically available.\n\nPotentially lost supply can include assets held in addresses that have remained inactive for many years.\n\nIt is impossible to prove that most dormant addresses are permanently inaccessible.\n\nThe owner may reappear.\n\nAnalysts should avoid subtracting all old supply from circulation without clear justification.\n\nLost-coin estimates are useful for scenario analysis but remain uncertain.\n\n### Miner and Validator Cohorts\n\nMiners and validators receive protocol rewards and may need to sell part of them to cover operating costs, taxes or infrastructure.\n\nTheir behaviour can affect market supply.\n\nProof-of-work miners may sell assets to fund electricity and equipment.\n\nProof-of-stake validators may sell rewards while retaining their principal stake.\n\nA rise in miner or validator transfers to exchanges may suggest increasing sell-side pressure.\n\nThe impact depends on reward size relative to broader market volume.\n\n### Miner Reserves\n\nMiner reserve metrics estimate assets held in labelled miner or mining-pool wallets.\n\nRising reserves may suggest that miners are retaining more rewards.\n\nFalling reserves may suggest distribution.\n\nMining pools may distribute rewards to individual miners, causing reserves to decline without direct market selling.\n\nEntity labels and payout structures must be considered.\n\n### Treasury Cohorts\n\nProject treasuries, foundations and decentralised organisations can control large token balances.\n\nTreasury spending may fund development, grants, liquidity and operations.\n\nIt can also create market selling pressure.\n\nA healthy analysis considers the size, frequency and purpose of treasury transfers.\n\nTreasury diversification from the native token into stable assets may reduce organisational risk while adding short-term token supply.\n\n### Insider and Team Wallets\n\nTeam, founder and early-investor wallets deserve particular attention because they may hold large low-cost allocations.\n\nRelevant questions include whether tokens are locked, when they become transferable and where they move after unlocking.\n\nA transfer from a vesting contract to a team wallet is not proof of sale.\n\nA later transfer to an exchange may increase the probability of distribution.\n\nPublic labels can be incomplete, so conclusions should remain cautious.\n\n### Airdrop Recipient Behaviour\n\nAirdrop recipients often receive tokens at little or no direct financial cost.\n\nThey may be more willing to sell than investors who purchased the asset.\n\nOn-chain analysis can track how much airdropped supply is:\n\nClaimed\n\nSold\n\nStaked\n\nHeld\n\nTransferred into DeFi\n\nHigh immediate selling may create early market pressure.\n\nHigh retention may indicate community confidence, ineligibility to sell or insufficient liquidity.\n\nThe behaviour should be compared with incentive design and user quality.\n\n### New Buyer Cohorts\n\nNew buyers can be identified approximately through recently created positions or recently moved supply.\n\nDuring a market rally, new participants may enter at progressively higher cost bases.\n\nIf price reverses, these cohorts move quickly into loss.\n\nThe distribution of cost basis can reveal where groups may seek to exit near break-even.\n\nIt can also show where previous demand entered the market.\n\nThese levels are behavioural reference areas, not fixed technical barriers.\n\n### Cost-Basis Distribution\n\nCost-basis distribution estimates how much supply last moved at different price levels.\n\nA large concentration at one price may indicate that many holders share a similar estimated entry.\n\nIf price falls below that zone, the holders may experience losses.\n\nIf price later recovers, some may sell near break-even.\n\nAlternatively, they may defend the area through additional purchases.\n\nThe chart shows potential pressure.\n\nPrice behaviour reveals how the cohort responds.\n\n### UTXO Realised Price Distribution\n\nOn UTXO networks, analysts can distribute supply according to the price at which outputs were created.\n\nThis can reveal areas where substantial coin volume last moved.\n\nIt resembles a form of on-chain volume profile.\n\nA high-volume cost-basis area may become an important psychological zone.\n\nThe metric differs from exchange volume profile because it tracks on-chain movement rather than trading volume on a venue.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,6,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-3-13-lesson-07','cognizen-crypto-mastery-foundations-production','Cost Basis and Support and Holder Behaviour During Bear Markets','cmf-module-3-13','text','### Cost Basis and Support\n\nAn aggregate cost-basis area may support price because holders resist selling below their entry or new buyers view the area as attractive.\n\nSupport is not guaranteed.\n\nIf negative information emerges, holders may rush to exit before losses become larger.\n\nA densely populated cost-basis zone can therefore produce either defence or accelerated selling.\n\nThe surrounding market regime determines which response is more likely.\n\n### Cost Basis and Resistance\n\nWhen price recovers toward the cost basis of holders who endured losses, those holders may sell near break-even.\n\nThis can create overhead supply.\n\nRepeated failure near the cohort’s cost basis may show that the market cannot absorb the exits.\n\nA decisive recovery and acceptance above it may indicate that demand has overcome the supply.\n\n### Profit-Taking by Cohort\n\nNot all profit-taking has the same market significance.\n\nShort-term holders may realise small gains frequently as part of normal trading.\n\nLong-term holders moving large old positions at substantial profits may create more meaningful supply.\n\nThe amount, age and destination of the assets should be considered together.\n\nA market absorbing long-term holder profit without losing price strength may demonstrate robust demand.\n\n### Capitulation by Cohort\n\nCapitulation describes widespread selling under stress.\n\nShort-term holders often capitulate first because their cost basis is high and conviction may be weaker.\n\nIn severe downturns, long-term holders may also begin realising losses.\n\nLong-term holder capitulation can indicate an advanced stage of market stress.\n\nIt does not guarantee that all selling is complete.\n\nFundamental failure can cause patient holders to continue exiting over an extended period.\n\n### Weak Hands and Strong Hands\n\nMarket commentary often refers to weak and strong hands.\n\nWeak hands are assumed to sell quickly under pressure, while strong hands tolerate volatility.\n\nThese labels are emotionally loaded and imprecise.\n\nA short-term trader who exits according to a stop is not necessarily irrational or weak.\n\nA long-term holder who refuses to respond to deteriorating fundamentals is not automatically strong.\n\nCohort analysis should describe observed holding behaviour without turning it into a judgement of investor quality.\n\n### Spent Volume Age Bands\n\nSpent Volume Age Bands classify transferred volume according to how long the assets had remained inactive.\n\nThis can reveal whether current spending is dominated by young or old supply.\n\nA market rally led mainly by young coins may involve active traders rotating the same supply.\n\nA rise in old-coin spending may indicate that long-term holders are distributing.\n\nThe metric becomes more informative when compared with total volume and price response.\n\n### Value Days Destroyed\n\nValue Days Destroyed extends coin-age concepts by including the market value of the moved assets.\n\nA large quantity of old coins moving at a high price produces a larger reading.\n\nThis may better reflect the economic importance of long-term holder spending than coin age alone.\n\nThe metric can still be distorted by custody transfers.\n\n### Liveliness\n\nLiveliness compares accumulated coin-age destruction with the total potential coin age created over time.\n\nA rising liveliness measure suggests that older supply is becoming more active.\n\nA falling measure suggests that holding and dormancy are dominating.\n\nLiveliness can provide a long-term view of accumulation and distribution.\n\nIt changes slowly and is more useful for structural analysis than precise short-term trading.\n\n### Vaultedness\n\nVaultedness is conceptually the opposite of liveliness.\n\nIt represents the tendency of supply to remain dormant and accumulate coin age.\n\nA growing vaultedness condition may suggest increasing long-term storage.\n\nThe balance between liveliness and vaultedness can help describe whether the market is dominated by spending or saving behaviour.\n\nThese are model-based concepts rather than direct observations of investor motivation.\n\n### Holder Behaviour During Bull Markets\n\nEarly in a bull market, long-term holders may remain relatively inactive while new demand begins lifting price.\n\nAs gains expand, some older supply may start moving.\n\nDistribution can increase during later stages as long-term holders realise larger profits.\n\nShort-term holders may become a greater share of active supply as new participants enter.\n\nThis progression is not identical in every cycle.\n\nInstitutional custody, financial products and changing market structure can alter cohort behaviour.\n\n### Holder Behaviour During Bear Markets\n\nDuring early declines, short-term holders may realise losses while many long-term holders continue holding.\n\nAs the decline deepens, new accumulation may occur among buyers with longer horizons.\n\nSevere stress can eventually cause some long-term holders to capitulate.\n\nA transition toward recovery may involve reduced realised loss, renewed accumulation and supply moving into older bands.\n\nThis process can take months or years.\n\nOne encouraging cohort metric does not confirm that the bear market has ended.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,7,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-3-13-lesson-08','cognizen-crypto-mastery-foundations-production','Holder Behaviour During Sideways Markets and Transaction Context','cmf-module-3-13','text','### Holder Behaviour During Sideways Markets\n\nDuring a range, supply may transfer gradually from impatient to patient holders or from long-term holders to new buyers.\n\nPrice alone may not reveal which process is occurring.\n\nCost-basis distribution, holder age and exchange flow data can provide additional evidence.\n\nA range with increasing older supply and declining exchange balances may support an accumulation interpretation.\n\nA range with rising old-coin spending and weakening demand may suggest distribution.\n\nThe eventual breakout provides confirmation.\n\n### Holder Behaviour and Volatility\n\nHigh volatility may activate different cohorts.\n\nShort-term holders respond quickly because their positions are closer to current market prices.\n\nLong-term holders may remain inactive during ordinary movement and become active only during exceptional rallies or crises.\n\nThis difference can help explain why volatility sometimes produces large transfers from newer to older holders or the reverse.\n\nThe behavioural pattern is probabilistic.\n\nIndividual participants do not all respond identically.\n\n### Holder Behaviour and Derivatives\n\nOn-chain holder data concerns movement of actual blockchain assets.\n\nDerivatives positions can create substantial economic exposure without immediate on-chain transfer.\n\nA long-term holder may hedge through futures while keeping coins inactive.\n\nOn-chain data would show continued holding even though the investor’s net directional exposure has been reduced.\n\nAn exchange may also use customer assets as part of complex derivative and custody operations.\n\nHolder analysis should therefore be combined with derivatives data when assessing market exposure.\n\n### Holder Behaviour and Exchange Flows\n\nExchange flows can help interpret cohort movement.\n\nOld coins becoming active and moving toward exchanges create a stronger possible distribution signal than old coins moving between self-custody addresses.\n\nShort-term holder losses combined with heavy exchange inflows may indicate capitulation.\n\nLarge withdrawals accompanied by rising long-term holder supply may support an accumulation interpretation.\n\nExchange labels and internal-transfer adjustments remain essential.\n\n### Holder Behaviour and Stablecoins\n\nStablecoin wallet cohorts can reveal changes in market liquidity and risk preference.\n\nLarge increases in stablecoins held on exchanges may create potential buying capacity.\n\nMovement into self-custody or lending protocols may reflect reserve management rather than immediate trading intent.\n\nWhale stablecoin activity can influence markets, but the same classification limitations apply.\n\nA custodian or issuer wallet should not be treated as one speculative holder.\n\n### Holder Behaviour in DeFi\n\nA wallet may hold tokens indirectly through lending, staking, liquidity pools and vaults.\n\nThe original asset may be locked while the user receives a derivative token.\n\nSimple balance analysis may underestimate or double count exposure.\n\nFor example, one asset may be deposited as collateral, borrowed against and redeployed elsewhere.\n\nEntity-level portfolio analysis across protocols is necessary to understand the full position.\n\nThis is technically difficult and often incomplete.\n\n### Wrapped Assets\n\nWrapped assets represent value from one network on another network.\n\nA custodian or bridge may hold the original asset while wrapped tokens circulate elsewhere.\n\nThe custody address can appear to be an enormous whale.\n\nIn reality, it backs many holders of the wrapped representation.\n\nAnalysts should classify bridge and wrapping contracts separately from ordinary holders.\n\n### Wallet Profitability\n\nSome analytics tools estimate whether particular wallets have traded profitably.\n\nThey may examine purchases, sales and current balances.\n\nThis can help identify historically successful entities.\n\nThe analysis has limitations.\n\nThe wallet may hold positions elsewhere, receive assets off-chain or use derivatives that are not visible.\n\nPast wallet performance does not prove future skill.\n\nCopying a visible transaction can also produce a worse entry after the market has already reacted.\n\n### Smart-Money Labels\n\nThe term smart money is sometimes applied to wallets associated with funds, skilled traders or early investors.\n\nThe label may be based on historical profitability, known identity or participation in successful projects.\n\nIt can be useful for research.\n\nIt can also create authority bias.\n\nA profitable wallet can make mistakes, hedge elsewhere or transfer assets for non-investment reasons.\n\nThe correct approach is to investigate the transaction, not imitate it automatically.\n\n### Wallet Tracking\n\nWallet tracking monitors selected addresses for new activity.\n\nIt may be used to follow:\n\nTeam wallets\n\nTreasuries\n\nLarge holders\n\nExploiters\n\nFunds\n\nMarket makers\n\nTracking can provide early evidence of asset movement.\n\nThe observer should account for false labels, address rotation and incomplete visibility.\n\nPublic wallet tracking should also be conducted responsibly and without unsupported claims about private individuals.\n\n### Transaction Context\n\nA wallet transaction should be examined through its complete context.\n\nImportant details include the sending entity, receiving entity, token, amount, historical wallet behaviour and any related contract calls.\n\nA transfer into a lending protocol has a different meaning from a transfer into an exchange deposit address.\n\nA bridge transfer may create an asset representation elsewhere rather than remove the holder’s market exposure.\n\nContext converts a raw movement into a more credible economic interpretation.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,8,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-3-13-lesson-09','cognizen-crypto-mastery-foundations-production','Behavioural Change and Example: Long-Term Holder Distribution','cmf-module-3-13','text','### Behavioural Change\n\nA change in a holder’s established behaviour may be more informative than the absolute balance.\n\nSuppose a long-dormant treasury begins making frequent exchange deposits.\n\nThe change deserves investigation.\n\nSimilarly, a large entity that normally distributes supply begins accumulating consistently.\n\nBehavioural change can indicate a new strategy, financial pressure or operational transition.\n\nOne action may be noise.\n\nA repeated pattern is more meaningful.\n\n### Cohort Migration\n\nSupply migrates between cohorts as assets move and age.\n\nRecently purchased coins become long-term holdings if they remain inactive.\n\nOld supply returns to short-term bands when it moves.\n\nThis migration can reveal how ownership is changing.\n\nA healthy accumulation phase may involve short-term supply gradually maturing into long-term supply.\n\nA distribution phase may involve older supply becoming young again as it transfers to new holders.\n\n### Supply Maturation\n\nSupply maturation occurs when assets remain inactive long enough to move into older age categories.\n\nA rise in maturing supply may indicate that recent buyers are becoming longer-term holders.\n\nThis can reduce immediate market availability.\n\nMaturation is not permanent.\n\nA later price event can reactivate the same supply.\n\nThe process should be viewed as changing probability of spending, not removing the asset from circulation permanently.\n\n### Supply Rejuvenation\n\nSupply rejuvenation occurs when old assets move and return to younger age bands.\n\nA large rejuvenation event can signal long-term holder activity.\n\nDuring strong market appreciation, this may represent profit-taking.\n\nDuring stress, it may indicate capitulation or collateral movement.\n\nThe term describes the age reset, not the economic purpose.\n\n### Cohort Divergence\n\nCohorts may behave differently at the same time.\n\nSmall holders may accumulate while whales distribute.\n\nLong-term holders may take profit while short-term holders buy aggressively.\n\nValidators may sell rewards while institutional custodians increase balances.\n\nThese divergences reveal how ownership is transferring.\n\nThe analyst should avoid describing the entire market as accumulating or distributing when different groups are doing opposite things.\n\n### Aggregation Risk\n\nAggregating all holders into one metric can hide important differences.\n\nFor example, overall exchange balances may remain stable while retail balances decline and institutional custody balances increase.\n\nA single network-wide realised price may conceal that recent buyers are in severe loss while long-term holders remain highly profitable.\n\nCohort analysis improves detail.\n\nIt can also become excessively complex.\n\nThe analyst should select groups relevant to the specific question.\n\n### Statistical Significance\n\nA wallet movement can appear dramatic without being economically important.\n\nThe amount should be compared with:\n\nCirculating supply\n\nDaily spot volume\n\nExchange depth\n\nHistorical cohort behaviour\n\nNormal transfer size\n\nA transfer involving one thousand tokens may be significant for a small illiquid project and irrelevant for a major network.\n\nPercentage and market-impact context matter.\n\n### Market Impact\n\nThe potential market impact of cohort distribution depends on whether the supply reaches a liquid venue and how quickly it is sold.\n\nA large holder can transfer assets to an exchange without selling immediately.\n\nThey may execute gradually, use over-the-counter markets or provide collateral.\n\nThe possible impact should be modelled rather than assumed.\n\nVisible movement creates risk awareness, not certainty about price direction.\n\n### Cohort Data and Market Timing\n\nHolder cohorts are generally more useful for understanding market structure and cycle conditions than for identifying exact entry points.\n\nLong-term holder distribution can continue for months while price rises.\n\nShort-term holder capitulation can occur repeatedly during a bear market.\n\nCohort signals should be combined with price confirmation, liquidity and market regime.\n\nThe data may indicate that risk is increasing before price reverses.\n\nIt rarely identifies the precise reversal candle.\n\n### A Practical Holder-Cohort Process\n\nBegin by defining the analytical question.\n\nIf the objective is to study long-term supply, examine holder age, dormancy and illiquid supply.\n\nIf the objective is to assess selling pressure, examine realised profit or loss, cohort spending and exchange destinations.\n\nIf the objective is to study ownership concentration, separate exchanges, custodians, protocols, vesting contracts and burn addresses from independent holders.\n\nNext, compare current behaviour with the cohort’s own history.\n\nDetermine whether the change is gradual, exceptional or related to a known event.\n\nFinally, combine the cohort evidence with price, exchange flows, derivatives and fundamental conditions.\n\nThe conclusion should explain both the likely interpretation and the strongest alternative explanation.\n\n### Example: Long-Term Holder Distribution\n\nSuppose price rises to a new cycle high.\n\nLong-Term Holder SOPR increases, old-coin spending rises and exchange deposits from labelled long-term wallets grow.\n\nPrice continues rising because spot demand remains strong.\n\nThe data suggests distribution, but not necessarily an immediate top.\n\nThe relevant warning appears if distribution accelerates while price fails to make further progress and demand weakens.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,9,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-3-13-lesson-10','cognizen-crypto-mastery-foundations-production','Example: Short-Term Holder Capitulation and Common Misunderstandings','cmf-module-3-13','text','### Example: Short-Term Holder Capitulation\n\nSuppose price falls below the short-term holder cost basis.\n\nShort-Term Holder SOPR remains below one and realised losses increase.\n\nOpen interest declines as leveraged longs are liquidated.\n\nThe combination suggests that newer participants are exiting under pressure.\n\nA durable recovery would require evidence that selling is declining and demand is returning.\n\n### Example: Apparent Whale Accumulation\n\nSuppose one address receives five percent of a token’s supply.\n\nSocial media describes the transfer as whale accumulation.\n\nFurther investigation shows that the address belongs to a newly created staking contract.\n\nThe beneficial owners have not necessarily changed.\n\nThe raw balance concentration is real.\n\nThe whale interpretation is false.\n\n### Example: Supply Maturation\n\nSuppose a large amount of supply acquired six months ago remains inactive and moves into a longer-term age band.\n\nExchange balances decline and realised loss activity diminishes.\n\nThis may indicate that weak selling has been absorbed and newer holders are becoming more patient.\n\nThe conclusion is strengthened if price forms improving long-term structure.\n\n### Example: Insider Distribution Risk\n\nSuppose an investor vesting contract releases a large token allocation.\n\nThe tokens move to several related wallets and later begin reaching exchange addresses.\n\nMarket liquidity is limited.\n\nThis creates a credible distribution risk.\n\nThe exact selling schedule remains unknown.\n\nThe appropriate response is to assess potential supply relative to market depth and monitor actual exchange activity.\n\n### Holder-Cohort Checklist\n\nBefore using holder data, determine whether the analysis concerns addresses, wallets, entities or coin units. Verify how the provider distinguishes among them.\n\nCheck whether exchanges, custodians, bridges, burn addresses, staking contracts and vesting wallets have been classified correctly.\n\nUnderstand the age or balance thresholds used to define each cohort.\n\nDetermine whether cost basis is a verified purchase price or an estimate based on the last on-chain movement.\n\nCompare the size of the cohort movement with circulating supply, market liquidity and historical behaviour.\n\nInvestigate where the assets moved and whether beneficial ownership appears to have changed.\n\nConsider alternative explanations such as custody restructuring, collateral movement, staking or bridging.\n\nFinally, require confirmation from price, spot volume, exchange flows or derivatives activity before converting the cohort observation into a trading conclusion.\n\n### Common Holder-Analysis Mistakes\n\nA common mistake is describing every large address as a whale. The address may belong to an exchange, custodian, bridge or protocol.\n\nAnother is assuming that long-term holders will continue holding indefinitely. Historical inactivity does not remove the possibility of future selling.\n\nAnalysts may treat last-moved price as the investor’s true cost basis even when assets were purchased off-chain or moved between self-controlled wallets.\n\nA further error is treating all old-coin movement as bearish. Long-dormant assets may move because of improved custody, inheritance, collateral or internal reorganisation.\n\nSome analysts label small holders as retail and large holders as institutions without evidence. Wallet balance alone does not reveal investor type.\n\nFinally, cohort data is often used to call exact market tops and bottoms. Holder behaviour can provide cycle context while remaining early, late or persistent for long periods.\n\n### Common Misunderstandings\n\n#### “One Large Address Represents One Whale”\n\nThe address may hold assets for many users or operate as a protocol contract.\n\n#### “Long-Term Holders Never Sell”\n\nThey have historically held for longer, but they can distribute, hedge or capitulate.\n\n#### “Recently Moved Coins Were Recently Purchased”\n\nA transfer may simply be a custody movement.\n\n#### “Old Coins Moving Means a Sale Is Imminent”\n\nThe movement increases potential availability but does not prove market selling.\n\n#### “Exchange Deposits Always Mean Distribution”\n\nThey can also represent collateral, market making or internal operations.\n\n#### “Small Addresses Represent Retail Investors”\n\nOne entity can divide assets among many small wallets.\n\n#### “Large Addresses Represent Institutions”\n\nThey may be exchanges, contracts, founders or aggregated user balances.\n\n#### “A Rising Supply in Profit Is Bearish”\n\nIt can continue rising throughout a healthy bull market.\n\n#### “A High Supply in Loss Means the Bottom Has Formed”\n\nLosses may persist or deepen during structural decline.\n\n#### “Realised Price Is Every Investor’s Average Purchase Price”\n\nIt is an on-chain estimate based on last movement.\n\n#### “Whale Tracking Reveals Smart-Money Intent”\n\nIt reveals wallet activity, not the complete portfolio or motivation.\n\n#### “More Dormant Supply Means No Selling Is Possible”\n\nDormant supply can become active at any time.\n\n#### “Cohort Analysis Predicts Exact Turning Points”\n\nIt is usually more reliable for structural context and risk assessment.','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,10,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-3-13-lesson-11','cognizen-crypto-mastery-foundations-production','Module Summary and Key Takeaway','cmf-module-3-13','text','### Module Summary\n\nWallet and holder-cohort analysis organises blockchain assets into groups according to holding period, balance size, cost basis and spending behaviour.\n\nThe distinction between an address, wallet and economic entity is essential.\n\nOne entity can control many addresses, while one exchange or custodian address can represent assets belonging to millions of customers.\n\nHolding-period analysis studies how long assets remain inactive.\n\nLong-term holders are generally less active, while short-term holders may be more sensitive to recent price movement.\n\nThese are behavioural classifications rather than fixed investor identities.\n\nCoin age, Coin Days Destroyed, dormancy, HODL waves and spent-volume age bands help identify whether current spending involves young or old supply.\n\nCost-basis metrics estimate the price at which assets last moved.\n\nThey can be calculated for long-term holders, short-term holders and other groups.\n\nPrice moving above or below a cohort cost basis may affect holder behaviour, but the level does not guarantee support or resistance.\n\nUnrealised profit and loss describe the financial position of holders who have not yet moved their assets.\n\nRealised profit, realised loss and SOPR estimate the economic result when assets move.\n\nThese metrics can provide evidence of profit-taking, distribution and capitulation.\n\nBalance cohorts may show whether smaller or larger entities are accumulating.\n\nThey must be adjusted for exchanges, custodians, smart contracts, burn addresses, bridges and vesting contracts.\n\nAccumulation and distribution are processes through which ownership transfers between cohorts.\n\nDistribution can occur while price continues rising, and accumulation can occur while price continues falling.\n\nHolder analysis is strongest when used to assess structural supply, market-cycle pressure and behavioural change.\n\nIt is weaker as a precise short-term timing tool.\n\nA blockchain can reveal that old assets moved, that recent holders are under pressure or that supply is becoming concentrated.\n\nIt cannot reveal the full identity, motivation or off-chain position of every participant.\n\n### Key Takeaway\n\nWallet behaviour can reveal how supply is moving between newer and older holders, profitable and unprofitable participants, and active and inactive entities.\n\nIt cannot reveal every investor’s identity or intention.\n\nA large transfer is not automatically a sale. A dormant wallet is not guaranteed to remain dormant. An exchange address is not one whale.\n\nUse holder cohorts to understand supply structure and behavioural pressure. Then require evidence from price, liquidity and market flows before turning that interpretation into a market decision.\n\nThe next module is 3.14: Exchange Inflows, Outflows and Reserve Analysis.','markdown',NULL,NULL,NULL,3,0,0,0,'',NULL,11,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `lessons` (`id`,`course_id`,`title`,`section_id`,`lesson_type`,`content`,`content_format`,`video_key`,`primary_asset_id`,`intro_asset_id`,`duration_minutes`,`is_preview`,`available_after_days`,`required_watch_percent`,`transcript`,`experience_json`,`position`,`updated_at`) SELECT 'cmf-module-3-13-lesson-12','cognizen-crypto-mastery-foundations-production','Check your understanding','cmf-module-3-13','text','### Check your understanding\n\nAnswer these questions to self-assess your understanding before moving on.\n\n1. What is a holder cohort?\n\n2. How does an address differ from a wallet and an entity?\n\n3. Why is entity adjustment important?\n\n4. How are long-term and short-term holders commonly distinguished?\n\n5. Why are holder thresholds not universal?\n\n6. What is dormant supply?\n\n7. Why might dormant supply include lost assets?\n\n8. What is reactivated supply?\n\n9. What is coin age?\n\n10. How is Coin Days Destroyed calculated?\n\n11. What does rising dormancy suggest?\n\n12. What are HODL waves?\n\n13. How do realised cap HODL waves differ from ordinary HODL waves?\n\n14. Why is last-moved price only an estimated cost basis?\n\n15. What is the short-term holder realised price?\n\n16. How may a cohort cost basis behave differently in bull and bear regimes?\n\n17. What is unrealised profit?\n\n18. What does NUPL attempt to measure?\n\n19. Why does high unrealised profit not guarantee an immediate market top?\n\n20. What is realised loss?\n\n21. What does SOPR measure?\n\n22. How does Long-Term Holder SOPR differ from Short-Term Holder SOPR?\n\n23. What are balance cohorts?\n\n24. Why must exchange wallets be removed from ordinary whale analysis?\n\n25. What can small-holder accumulation indicate?\n\n26. Why may large-address accumulation be misleading?\n\n27. What is whale distribution?\n\n28. Why should burn addresses be excluded from ownership concentration?\n\n29. How should vesting wallets be interpreted?\n\n30. What is accumulation?\n\n31. What is distribution?\n\n32. Why is distribution not automatically evidence of an immediate top?\n\n33. How does reaccumulation differ from redistribution?\n\n34. What is illiquid supply?\n\n35. Why is liquid supply not inherently bearish?\n\n36. What is a supply-shock thesis?\n\n37. Why are lost-coin estimates uncertain?\n\n38. How can miner or validator behaviour affect market supply?\n\n39. Why should treasury transfers be monitored?\n\n40. What additional risk accompanies insider wallet unlocks?\n\n41. How can airdrop recipients affect early token supply?\n\n42. What is cost-basis distribution?\n\n43. How can a cost-basis area act as support or resistance?\n\n44. What are Spent Volume Age Bands?\n\n45. What does liveliness measure?\n\n46. What is supply maturation?\n\n47. What is supply rejuvenation?\n\n48. What is cohort divergence?\n\n49. Why can aggregate holder metrics hide important differences?\n\n50. Why should wallet movements be compared with market liquidity?\n\n51. How can derivatives obscure an investor’s true exposure?\n\n52. Why can DeFi activity cause balance double counting?\n\n53. What is a wrapped asset?\n\n54. Why should “smart-money” labels be treated cautiously?\n\n55. What makes a change in historical wallet behaviour significant?\n\n56. Why are cohort metrics usually better for structural analysis than exact timing?\n\n57. What evidence would strengthen an interpretation of long-term holder distribution?\n\n58. What evidence may indicate short-term holder capitulation?\n\n59. Which alternative explanations should be considered when old assets move?\n\n60. Why should cohort analysis be combined with price and exchange-flow data?','markdown',NULL,NULL,NULL,6,0,0,0,'',NULL,12,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
--> statement-breakpoint
INSERT OR IGNORE INTO `course_sections` (`id`,`course_id`,`title`,`position`,`created_at`) SELECT 'cmf-module-3-14','cognizen-crypto-mastery-foundations-production','Module 3.14: Exchange Inflows, Outflows and Reserve Analysis',15,1785297600000 WHERE EXISTS (SELECT 1 FROM `courses` WHERE `id`='cognizen-crypto-mastery-foundations-production');
